/* StatsMgmtMapper.getTimerVal */
SELECT	ETC1 AS VAL
  FROM	CMN_GRP_CD_MST
 WHERE
  		GRP_ID = #{grpId}
   AND 	CD_VAL = #{cdVal}

mapper.sql:
SELECT SUB.CONTRACT_NUM , TO_CHAR(TO_DATE(SUB.LST_COM_ACTV_DATE,'YYYYMMDD'), 'YYYY-MM-DD') AS LST_COM_ACTV_DATE , DECODE(SUB.SUB_STATUS, 'C', TO_CHAR(TO_DATE(SUBSTR(SUB.SUB_STATUS_DATE, 1, 8), 'YYYYMMDD'), 'YYYY-MM-DD'), '') AS TMNT_DT , NVL(TRIM(SUBSTR(REQ.FST_MODEL_INFO, 21 , 30)), REQ.REQ_USIM_NAME) AS FST_MODEL_INFO , REQ.FST_RATE_CD , REQ.FST_RATE_NM , SUB.OPEN_AGNT_CD , FN_GET_ORGNM(SUB.OPEN_AGNT_CD) AS OPEN_AGNT_NM , FN_GET_AGE_JAVA(CRYPTO_AES256.DEC_AES(SUB.USER_SSN)) AS AGE , DECODE(MOD(SUBSTR(CRYPTO_AES256.DEC_AES(SUB.USER_SSN),7,1), 2), 1, '남', '여') AS SEX_NM , CASE WHEN DCH.CONTRACT_NUM IS NOT NULL AND DVC_REQ.OPER_TYPE = 'HDN3' THEN LRT.DATA_TYPE ELSE FRT.DATA_TYPE END AS DATA_TYPE , FN_GET_CODENM('RCP9004', CASE WHEN DCH.CONTRACT_NUM IS NOT NULL AND DVC_REQ.OPER_TYPE = 'HDN3' THEN 'MM' ELSE REQ.REQ_BUY_TYPE END ) AS REQ_BUY_TYPE , SUB.SUB_STATUS , FN_GET_CODENM('MSP0003', SUB.SUB_STATUS) AS SUB_STATUS_NM , TO_CHAR(TO_DATE(SUBSTR(REQ.SIM_INFO, 20, 8), 'YYYYMMDD'), 'YYYY-MM-DD') AS SIM_STRT_DT , FN_GET_CODENM('MSP0010', SUBSTR(REQ.SIM_INFO, 36, 1)) AS SIM_STAT_NM , TO_NUMBER(SUBSTR(REQ.SIM_INFO, 3, 3)) AS SIM_ENGG_CNT , TO_CHAR(TO_DATE(SUBSTR(REQ.SIM_INFO, 28, 8), 'YYYYMMDD'), 'YYYY-MM-DD') AS SIM_END_DT , SUB_LINK_NAME as CSTMR_NM , SUB_LINK_NAME AS SUB_LINK_NAME_MSK , FN_GET_CODENM('RCP0007', REQ.ON_OFF_TYPE ) AS ON_OFF_TYPE , AGR.DLVRY_NAME , AGR.DLVRY_MOBILE_FN || AGR.DLVRY_MOBILE_MN || AGR.DLVRY_MOBILE_RN AS PHON_CTN , AGR.DLVRY_POST , AGR.DLVRY_ADDR || AGR.DLVRY_ADDR_DTL AS DLVRY_FULL_ADDR , AGR.DLVRY_ADDR , AGR.DLVRY_ADDR_DTL , PRESENT_CODE , (SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'presentCode' AND DTL_CD = AGR.PRESENT_CODE ) AS PRESENT_NM , AGRM_MEMO , AGR.SEQ , SUB.SUBSCRIBER_NO FROM MSP_JUO_SUB_INFO SUB , MSP_REQUEST_DTL REQ , MSP_DVC_CHG_AGNT_HST DCH , MSP_REQUEST DVC_REQ , MSP_RATE_MST FRT , MSP_RATE_MST LRT , (SELECT B.CONTRACT_NUM, B.SEQ, B.DLVRY_NAME, B.DLVRY_MOBILE_FN, B.DLVRY_MOBILE_MN, B.DLVRY_MOBILE_RN, B.DLVRY_POST, B.DLVRY_ADDR, B.DLVRY_ADDR_DTL, B.PRESENT_CODE, B.AGRM_MEMO, NVL(B.ORDER_TYPE, '01') AS ORDER_TYPE, B.REGST_DTTM FROM (SELECT CONTRACT_NUM , MAX(SEQ) AS SEQ FROM MCP_REQUEST_AGRM@DL_MCP GROUP BY CONTRACT_NUM) A , MCP_REQUEST_AGRM@DL_MCP B WHERE A.CONTRACT_NUM = B.CONTRACT_NUM AND A.SEQ = B.SEQ) AGR WHERE SUB.PPPO = 'PO' AND SUB.CONTRACT_NUM = REQ.CONTRACT_NUM AND REQ.SIM_INFO IS NOT NULL AND REQ.FST_RATE_CD = FRT.RATE_CD AND REQ.LST_RATE_CD = LRT.RATE_CD AND REQ.CONTRACT_NUM = AGR.CONTRACT_NUM(+) AND AGR.REGST_DTTM(+) BETWEEN TO_DATE(SUBSTR(REQ.SIM_INFO, 20, 8) , 'YYYYMMDD') AND TO_DATE(SUBSTR(REQ.SIM_INFO, 20, 8), 'YYYYMMDD') + 7 AND SUB.CONTRACT_NUM = DCH.CONTRACT_NUM(+) AND DCH.APPL_END_DTTM(+) = '99991231000000' AND DCH.REQUEST_KEY(+) IS NOT NULL AND DCH.REQUEST_KEY = DVC_REQ.REQUEST_KEY(+)
AND SUBSTR(REQ.SIM_INFO, 20, 8) BETWEEN #{srchStrtDt} AND #{srchEndDt}
AND SUB.SUB_STATUS = #{subStatus}
AND (SUB.CONTRACT_NUM = #{searchName} OR SUB.CONTRACT_NUM = (SELECT DISTINCT CONTRACT_NUM FROM MSP_JUO_SUB_INFO_HIST WHERE SVC_CNTR_NO = #{searchName}))
AND SUB.SUB_LINK_NAME LIKE #{searchName} || '%'
AND SUB.SUBSCRIBER_NO = #{searchName}
AND REQ.ON_OFF_TYPE = #{onOffType}
AND AGR.ORDER_TYPE = #{orderType}
ORDER BY SIM_STRT_DT DESC, SUB.SUB_STATUS, SUB.OPEN_AGNT_CD

SELECT A.PRC_MST_SEQ ,A.PRC_DTL_SEQ
/*평생할인 자동가입 지연 현황 화면인 경우만 조회*/ ,CASE WHEN A.RSLT_CD != '0000' THEN /*실패인 경우 - 현재날짜가 지연일수의 기준점*/ (SELECT TO_DATE(TO_CHAR(SYSDATE, 'YYYYMMDD'),'YYYYMMDD') - TO_DATE(B.EFFECTIVE_DT, 'YYYYMMDD') || '일' FROM MSP_DIS_PRC_MST B WHERE A.PRC_MST_SEQ = B.PRC_MST_SEQ) ELSE /*성공인 경우 - 부가서비스 가입 일자가 지연일수의 기준점*/ (SELECT TO_DATE(TO_CHAR(A.REGST_DTTM, 'YYYYMMDD'),'YYYYMMDD') - TO_DATE(B.EFFECTIVE_DT, 'YYYYMMDD') || '일' FROM MSP_DIS_PRC_MST B WHERE A.PRC_MST_SEQ = B.PRC_MST_SEQ) END DELAY_DT
/* 수동 처리 한 경우, 지연일수는 수동처리일시가 기준점*/ ,(SELECT PROC_YN FROM MSP_DIS_PRC_MST B WHERE A.PRC_MST_SEQ = B.PRC_MST_SEQ) AS PROC_YN ,(SELECT TO_DATE(TO_CHAR(B.PROC_DATE, 'YYYYMMDD'),'YYYYMMDD') - TO_DATE(B.EFFECTIVE_DT , 'YYYYMMDD') || '일' FROM MSP_DIS_PRC_MST B WHERE A.PRC_MST_SEQ = B.PRC_MST_SEQ) AS PROC_DATE
,A.CONTRACT_NUM ,TO_CHAR(A.REGST_DTTM, 'YYYYMMDDHH24MISS') AS REGST_DTTM ,A.SOC ,NVL((SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID ='RCP2042' AND CD_VAL = A.SOC), A.SOC) AS SOC_NM ,A.RSLT_CD AS SUCC_YN ,DECODE(A.RSLT_CD , '0000' , '성공' , '실패') AS SUCC_YN_NM ,DECODE(A.RSLT_CD , '0000' , '' , A.PRCS_SBST) AS FAIL_RS_NM ,A.PROC_ID ,A.PROC_NM
,A.TB_NM ,TO_CHAR(A.SEQ) AS SEQ
FROM ( SELECT PRC_MST_SEQ ,PRC_DTL_SEQ ,CONTRACT_NUM ,REGST_DTTM ,SOC ,RSLT_CD ,PRCS_SBST ,'' AS PROC_ID ,'' AS PROC_NM ,SEQ ,'DTL' AS TB_NM FROM MSP_DIS_PRC_DTL WHERE PRC_MST_SEQ = #{prcMstSeq}
AND PRC_DTL_SEQ = #{prcDtlSeq}
UNION ALL SELECT PRC_MST_SEQ ,PRC_DTL_SEQ ,CONTRACT_NUM ,PROC_DTTM AS REGST_DTTM ,SOC ,RSLT_CD ,PRCS_SBST ,PROC_ID ,F_GET_ADMIN_NM(PROC_ID) AS PROC_NM ,SEQ ,'RTY' AS TB_NM FROM MSP_DIS_PRC_RTY WHERE PRC_MST_SEQ = #{prcMstSeq}
AND PRC_DTL_SEQ = #{prcDtlSeq}
) A
/* 평생할인 자동가입 지연 현황 */ ORDER BY PRC_DTL_SEQ DESC, REGST_DTTM DESC
/* 평생할인 자동가입 현황 */ ORDER BY REGST_DTTM DESC, PRC_DTL_SEQ DESC

mapper.select:
/* StatsMgmtMapper.getStatsSimListExcel */ SELECT SUB.CONTRACT_NUM , SUBSTR(JAI.SIM_START_DT,0,8) AS SIM_STRT_DT , DECODE(JAI.APP_END_DATE, '99991231000000', SUBSTR(JAI.SIM_END_DT,0,8), SUBSTR(JAI.APP_END_DATE,0,8)) AS SIM_END_DT , CASE WHEN TO_DATE(JAI.APP_END_DATE, 'YYYYMMDDHH24MISS') < SYSDATE THEN '해지' WHEN JAI.APP_END_DATE = '99991231000000' THEN CASE WHEN TO_DATE(JAI.SIM_END_DT, 'YYYYMMDDHH24MISS') < SYSDATE THEN '해지' ELSE '사용중' END ELSE '사용중' END AS SIM_STAT_NM , TO_CHAR(TO_DATE(SUB.LST_COM_ACTV_DATE,'YYYYMMDD'), 'YYYY-MM-DD') AS LST_COM_ACTV_DATE , DECODE(SUB.SUB_STATUS, 'C', TO_CHAR(TO_DATE(SUBSTR(SUB.SUB_STATUS_DATE, 1, 8), 'YYYYMMDD'), 'YYYY-MM-DD'), '') AS TMNT_DT , NVL(TRIM(SUBSTR(REQ.FST_MODEL_INFO, 21 , 30)), REQ.REQ_USIM_NAME) AS FST_MODEL_INFO , REQ.FST_RATE_CD , REQ.FST_RATE_NM , SUB.OPEN_AGNT_CD , FN_GET_ORGNM(SUB.OPEN_AGNT_CD) AS OPEN_AGNT_NM , FN_GET_AGE_JAVA(CRYPTO_AES256.DEC_AES(SUB.USER_SSN)) AS AGE , DECODE(MOD(SUBSTR(CRYPTO_AES256.DEC_AES(SUB.USER_SSN),7,1), 2), 1, '남', '여') AS SEX_NM , CASE WHEN DCH.CONTRACT_NUM IS NOT NULL AND DVC_REQ.OPER_TYPE = 'HDN3' THEN LRT.DATA_TYPE ELSE FRT.DATA_TYPE END AS DATA_TYPE , FN_GET_CODENM('RCP9004', CASE WHEN DCH.CONTRACT_NUM IS NOT NULL AND DVC_REQ.OPER_TYPE = 'HDN3' THEN 'MM' ELSE REQ.REQ_BUY_TYPE END ) AS REQ_BUY_TYPE , SUB.SUB_STATUS , FN_GET_CODENM('MSP0003', SUB.SUB_STATUS) AS SUB_STATUS_NM , TO_NUMBER(SUBSTR(REQ.SIM_INFO, 3, 3)) AS SIM_ENGG_CNT , SUB_LINK_NAME as CSTMR_NM , SUB_LINK_NAME AS SUB_LINK_NAME_MSK , FN_GET_CODENM('RCP0007', REQ.ON_OFF_TYPE ) AS ON_OFF_TYPE , AGR.DLVRY_NAME , AGR.DLVRY_MOBILE_FN || AGR.DLVRY_MOBILE_MN || AGR.DLVRY_MOBILE_RN AS PHON_CTN , AGR.DLVRY_POST , AGR.DLVRY_ADDR || AGR.DLVRY_ADDR_DTL AS DLVRY_FULL_ADDR , AGR.DLVRY_ADDR , AGR.DLVRY_ADDR_DTL , PRESENT_CODE , (SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'presentCode' AND DTL_CD = AGR.PRESENT_CODE ) AS PRESENT_NM , AGRM_MEMO , AGR.SEQ , SUB.SUBSCRIBER_NO FROM MSP_JUO_SUB_INFO SUB , MSP_REQUEST_DTL REQ , MSP_DVC_CHG_AGNT_HST DCH , MSP_REQUEST DVC_REQ , MSP_RATE_MST FRT , MSP_RATE_MST LRT , MSP_JUO_ADD_INFO JAI , (SELECT B.CONTRACT_NUM, B.SEQ, B.DLVRY_NAME, B.DLVRY_MOBILE_FN, B.DLVRY_MOBILE_MN, B.DLVRY_MOBILE_RN, B.DLVRY_POST, B.DLVRY_ADDR, B.DLVRY_ADDR_DTL, B.PRESENT_CODE, B.AGRM_MEMO FROM (SELECT CONTRACT_NUM , MAX(SEQ) AS SEQ FROM MCP_REQUEST_AGRM@DL_MCP GROUP BY CONTRACT_NUM) A , MCP_REQUEST_AGRM@DL_MCP B WHERE A.CONTRACT_NUM = B.CONTRACT_NUM AND A.SEQ = B.SEQ) AGR WHERE SUB.PPPO = 'PO' AND SUB.CONTRACT_NUM = REQ.CONTRACT_NUM AND REQ.SIM_INFO IS NOT NULL AND REQ.FST_RATE_CD = FRT.RATE_CD AND REQ.LST_RATE_CD = LRT.RATE_CD AND SUB.CONTRACT_NUM = AGR.CONTRACT_NUM(+) AND SUB.CONTRACT_NUM = DCH.CONTRACT_NUM(+) AND DCH.APPL_END_DTTM(+) = '99991231000000' AND DCH.REQUEST_KEY(+) IS NOT NULL AND DCH.REQUEST_KEY = DVC_REQ.REQUEST_KEY(+) AND SUB.CONTRACT_NUM = JAI.CONTRACT_NUM AND JAI.EVNT_CD = 'SIM' AND JAI.GRNT_INSR_STAT_CD = 'A'
AND SUBSTR(JAI.SIM_START_DT, 0, 8) BETWEEN #{srchStrtDt} AND #{srchEndDt}
AND SUB.SUB_STATUS = #{subStatus}
AND (SUB.CONTRACT_NUM = #{searchName} OR SUB.CONTRACT_NUM = (SELECT DISTINCT CONTRACT_NUM FROM MSP_JUO_SUB_INFO_HIST WHERE SVC_CNTR_NO = #{searchName}))
AND SUB.SUB_LINK_NAME LIKE #{searchName} || '%'
AND SUB.SUBSCRIBER_NO = #{searchName}
AND REQ.ON_OFF_TYPE = #{onOffType}
ORDER BY CONTRACT_NUM DESC, JAI.SIM_START_DT, SUB.SUB_STATUS, SUB.OPEN_AGNT_CD

mapper.update:
		UPDATE MCP_REQUEST_AGRM@DL_MCP  /* StatsMgmtMapper.updateDlvryInfo */
		SET 
            DLVRY_NAME = #{dlvryName, jdbcType=VARCHAR}
           , DLVRY_MOBILE_FN = #{phonCtn1, jdbcType=VARCHAR}
           , DLVRY_MOBILE_MN = #{phonCtn2, jdbcType=VARCHAR} 
           , DLVRY_MOBILE_RN = #{phonCtn3, jdbcType=VARCHAR}
           , DLVRY_POST = #{dlvryPost, jdbcType=VARCHAR} 
           , DLVRY_ADDR = #{dlvryAddr, jdbcType=VARCHAR}
           , DLVRY_ADDR_DTL = #{dlvryAddrDtl, jdbcType=VARCHAR}
           , AGRM_MEMO = #{agrmMemo, jdbcType=VARCHAR}
           , RVISN_DTTM = SYSDATE
        WHERE CONTRACT_NUM = #{contractNum}
             AND SEQ = #{seq}

mapper.select:
/* StatsMgmtMapper.getStatsOsstMgmtDaily */
SELECT RSLT_CD, PRGR_STAT_CD, '['||PRGR_STAT_CD||']'||FN_GET_CODENM('RCP2040',PRGR_STAT_CD) AS PRGR_STAT_NM, DECODE(RSLT_CD, 'ITL_SST_E1014',SUBSTR(RSLT_MSG,14), '2028',SUBSTR(SUBSTR(RSLT_MSG,INSTR(RSLT_MSG,']')+2),0,21), '2202',SUBSTR(RSLT_MSG,0,7), '2205',SUBSTR(RSLT_MSG,0,20), '2206',SUBSTR(RSLT_MSG,0,22), '2302',SUBSTR(RSLT_MSG,0,15), '2412',SUBSTR(RSLT_MSG,0,12), '2413',SUBSTR(RSLT_MSG,0,30), '3105','해당상품은 '||SUBSTR(RSLT_MSG,INSTR(RSLT_MSG,']')+4), '3107',SUBSTR(RSLT_MSG,0,13), '3114',SUBSTR(RSLT_MSG,0,12), 'MCG_BIZ_E0421',SUBSTR(RSLT_MSG,0,18), 'ITL_SST_E1018','개통 불가능 고객', 'ITL_SST_E1020',SUBSTR(RSLT_MSG,0,13), 'ITL_COM_E0003','상세내용확인', '9000','상세내용확인', '9001',SUBSTR(RSLT_MSG,INSTR(RSLT_MSG,']')+2), RSLT_MSG) AS RSLT_MSG, COUNT(*) AS ERR_CNT FROM MCP_REQUEST_OSST@DL_MCP WHERE TO_CHAR(REGST_DTTM,'YYYYMMDD') = #{stdrDate} AND RSLT_CD NOT IN ('N', '0000')
AND RSLT_CD = #{errCd}
AND PRGR_STAT_CD = #{eventCd}
GROUP BY RSLT_CD, PRGR_STAT_CD, DECODE(RSLT_CD, 'ITL_SST_E1014',SUBSTR(RSLT_MSG,14), '2028',SUBSTR(SUBSTR(RSLT_MSG,INSTR(RSLT_MSG,']')+2),0,21), '2202',SUBSTR(RSLT_MSG,0,7), '2205',SUBSTR(RSLT_MSG,0,20), '2206',SUBSTR(RSLT_MSG,0,22), '2302',SUBSTR(RSLT_MSG,0,15), '2412',SUBSTR(RSLT_MSG,0,12), '2413',SUBSTR(RSLT_MSG,0,30), '3105','해당상품은 '||SUBSTR(RSLT_MSG,INSTR(RSLT_MSG,']')+4), '3107',SUBSTR(RSLT_MSG,0,13), '3114',SUBSTR(RSLT_MSG,0,12), 'MCG_BIZ_E0421',SUBSTR(RSLT_MSG,0,18), 'ITL_SST_E1018','개통 불가능 고객', 'ITL_SST_E1020',SUBSTR(RSLT_MSG,0,13), 'ITL_COM_E0003','상세내용확인', '9000','상세내용확인', '9001',SUBSTR(RSLT_MSG,INSTR(RSLT_MSG,']')+2), RSLT_MSG) ORDER BY RSLT_CD,PRGR_STAT_CD

/* StatsMgmtMapper.getStatsBillingStatList */
SELECT BIL.CONTRACT_NUM AS CONTRACT_NUM /* 계약번호 */ , BIL.SUB_LINK_NM AS CSTMR_NM /* 고객명 */ , TO_CHAR(TO_DATE(BIL.LST_COM_ACTV_DATE,'YYYYMMDD'), 'YYYY-MM-DD') AS LST_COM_ACTV_DATE /* 개통일 */ , BIL.MOBILE_NO AS ctn /* 전화번호 */ , BIL.AGE AS age /* 나이 */ , (SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = BIL.OPEN_AGNT_CD AND ROWNUM = 1) AS OPEN_AGNT_NM /* 개통대리점 */ , FN_GET_CODENM('RCP0007', DTL.ON_OFF_TYPE) AS ON_OFF_TYPE /* 모집유형 */ , FN_GET_ORGNM(BIL.ORG_ID) AS FST_USIM_ORG_NM /* 유심접점 */ , CASE WHEN SUBSTR(REPLACE(CRYPTO_AES256.DEC_AES(SUB.USER_SSN), '-', ''), 7, 1) IN ('1' , '3' , '5' , '7') THEN '남자' WHEN SUBSTR(REPLACE(CRYPTO_AES256.DEC_AES(SUB.USER_SSN), '-', ''), 7, 1) IN ('2' , '4' , '6' , '8') THEN '여자' END gender /* 성별 */ , TO_CHAR(BIL.RDT, 'YYYY-MM-DD HH24:MI:SS' ) AS RDT /* 등록일 */ , BIL.BILL_TYPE_CD AS BILL_TYPE_CD /* 재발행유형 코드(1:이메일,2:MMS) */ , DECODE(BILL_TYPE_CD , '1' , BIL.BILL_AD_INFO , '' ) AS BILL_AD_INFO1 /* 재발행주소(EMAIL) */ , DECODE(BILL_TYPE_CD , '2' , BIL.BILL_AD_INFO , '' ) AS BILL_AD_INFO2 /* 재발행주소(MMS) */ , DECODE(BIL.SUCCESS_YN, 'Y' , '성공', '실패') AS SUCCESS_YN /* 성공여부(Y,N) */ FROM NMCP_BILLCHRG_RESEND@DL_MCP BIL ,MSP_JUO_SUB_INFO SUB ,MSP_REQUEST_DTL DTL WHERE BIL.CONTRACT_NUM = SUB.CONTRACT_NUM(+) AND SUB.CONTRACT_NUM = DTL.CONTRACT_NUM(+)
AND BIL.RDATE BETWEEN #{srchStrtDt} AND #{srchEndDt}
AND (BIL.CONTRACT_NUM = #{searchName} OR BIL.CONTRACT_NUM = (SELECT DISTINCT CONTRACT_NUM FROM MSP_JUO_SUB_INFO_HIST WHERE SVC_CNTR_NO = #{searchName}))
AND BIL.MOBILE_NO = #{searchName}
AND (BIL.SUCCESS_YN = #{successYn} OR SUCCESS_YN IS NULL)
AND BIL.SUCCESS_YN = #{successYn}
ORDER BY BIL.RDT DESC

/* StatsMgmtMapper.getStatsBillingStatListExcel */ SELECT BIL.CONTRACT_NUM AS CONTRACT_NUM /* 계약번호 */ , BIL.SUB_LINK_NM AS CSTMR_NM /* 고객명 */ , TO_CHAR(TO_DATE(BIL.LST_COM_ACTV_DATE,'YYYYMMDD'), 'YYYY-MM-DD') AS LST_COM_ACTV_DATE /* 개통일 */ , BIL.MOBILE_NO AS ctn /* 전화번호 */ , BIL.AGE AS age /* 나이 */ , (SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = BIL.OPEN_AGNT_CD AND ROWNUM = 1) AS OPEN_AGNT_NM /* 개통대리점 */ , FN_GET_CODENM('RCP0007', DTL.ON_OFF_TYPE) AS ON_OFF_TYPE /* 모집유형 */ , FN_GET_ORGNM(BIL.ORG_ID) AS FST_USIM_ORG_NM /* 유심접점 */ , CASE WHEN SUBSTR(REPLACE(CRYPTO_AES256.DEC_AES(SUB.USER_SSN), '-', ''), 7, 1) IN ('1' , '3' , '5' , '7') THEN '남자' WHEN SUBSTR(REPLACE(CRYPTO_AES256.DEC_AES(SUB.USER_SSN), '-', ''), 7, 1) IN ('2' , '4' , '6' , '8') THEN '여자' END gender /* 성별 */ , TO_CHAR(BIL.RDT, 'YYYY-MM-DD HH24:MI:SS' ) AS RDT /* 등록일 */ , BIL.BILL_TYPE_CD AS BILL_TYPE_CD /* 재발행유형 코드(1:이메일,2:MMS) */ , DECODE(BILL_TYPE_CD , '1' , BIL.BILL_AD_INFO , '' ) AS BILL_AD_INFO1 /* 재발행주소(EMAIL) */ , DECODE(BILL_TYPE_CD , '2' , BIL.BILL_AD_INFO , '' ) AS BILL_AD_INFO2 /* 재발행주소(MMS) */ , DECODE(BIL.SUCCESS_YN, 'Y' , '성공', '실패') AS SUCCESS_YN /* 성공여부(Y,N) */ FROM NMCP_BILLCHRG_RESEND@DL_MCP BIL ,MSP_JUO_SUB_INFO SUB ,MSP_REQUEST_DTL DTL WHERE BIL.CONTRACT_NUM = SUB.CONTRACT_NUM(+) AND SUB.CONTRACT_NUM = DTL.CONTRACT_NUM(+)
AND BIL.RDATE BETWEEN #{srchStrtDt} AND #{srchEndDt}
AND (BIL.CONTRACT_NUM = #{searchName} OR BIL.CONTRACT_NUM = (SELECT DISTINCT CONTRACT_NUM FROM MSP_JUO_SUB_INFO_HIST WHERE SVC_CNTR_NO = #{searchName}))
AND BIL.MOBILE_NO = #{searchName}
AND (BIL.SUCCESS_YN = #{successYn} OR SUCCESS_YN IS NULL)
AND BIL.SUCCESS_YN = #{successYn}
ORDER BY BIL.RDT DESC

/* StatsMgmtMapper.getCallList */
SELECT SEL.CUST_REQ_SEQ AS CUST_REQ_SEQ /* 시퀀스 */ , SEL.CONTRACT_NUM AS SVC_CONT_ID /* 계약번호 */ , SEL.CONTRACT_NUM AS CONTRACT_NUM /* 계약번호 */ , SUB.ON_OFF_TYPE AS ON_OFF_TYPE /* 모집경로 */ , (SELECT COUNT(*) FROM EMV_SCAN_FILE@DL_MCP WHERE SCAN_ID = SUB.SCAN_ID ) AS SCAN_FILE_CNT /* 파일건수 */ , SUB.SCAN_ID AS SCAN_ID /* 스캔ID */ , DTL.RES_NO AS RES_NO /* 예약번호 */ , SEL.CSTMR_NAME AS SUB_LINK_NAME /* 고객명 */ , TO_CHAR(TO_DATE(SUB.LST_COM_ACTV_DATE,'YYYYMMDD'), 'YYYY-MM-DD') AS LST_COM_ACTV_DATE /* 개통일 */ , SEL.MOBILE_NO AS CTN /* 전화번호 */ , FN_GET_AGE_JAVA(CRYPTO_AES256.DEC_AES(SUB.USER_SSN)) AS AGE /* 나이 */ , CASE WHEN SUBSTR(REPLACE(CRYPTO_AES256.DEC_AES(SUB.USER_SSN), '-', ''), 7, 1) IN ('1' , '3' , '5' , '7') THEN '남자' WHEN SUBSTR(REPLACE(CRYPTO_AES256.DEC_AES(SUB.USER_SSN), '-', ''), 7, 1) IN ('2' , '4' , '6' , '8') THEN '여자' END GENDER /* 성별 */ , (SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = SUB.OPEN_AGNT_CD AND ROWNUM = 1) AS OPEN_AGNT_NM /* 개통대리점 */ , FN_GET_CODENM('RCP0007', DTL.ON_OFF_TYPE) AS ON_OFF_TYPE_NM /* 모집유형 */ , (SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'CL02' AND DTL_CD = CAL.RECV_TYPE) AS RECV_TYPE /* 수신방법 */ , (SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'CL01' AND DTL_CD = CAL.PROC_CD) AS PROC_CD_NM /* 결과 */ , CAL.PROC_CD AS PROC_CD /* 결과코드 */ , TO_CHAR(CAL.SYS_RDATE, 'YYYY-MM-DD HH24:MI:SS' ) AS SYS_RDATE /* 등록일 */ , TO_CHAR(CAL.SYS_UDATE, 'YYYY-MM-DD HH24:MI:SS' ) AS SYS_UDATE /* 수정일 */ , (SELECT USR_NM FROM CMN_USR_MST WHERE USR_ID = CAL.UPDT_ID) AS UPDT_ID /* 수정자 */ , CAL.START_DATE AS START_DATE /* 시작일자 */ , CAL.END_DATE AS END_DATE /* 종료일자 */ , CAL.CL_MEMO AS CL_MEMO /* 메모 */ , (SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'CL03' AND DTL_CD = CAL.CALL_TYPE) AS CALL_TYPE /* 열람종류 */ , CAL.TYPE_VOICE AS TYPE_VOICE /* 음성 */ , CAL.TYPE_TEXT AS TYPE_TEXT /* 문자 */ , CAL.TYPE_DATA AS TYPE_DATA /* 데이터 */ , CAL.TYPE_VOICE_TEXT AS TYPE_VOICE_TEXT /* 음성+문자 */ , CAL.TYPE_ALL AS TYPE_ALL /* 음성+문자+데이터 */ , (SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'CL04' AND DTL_CD = CAL.REQ_RSN) AS REQ_RSN /* 신청사유 */ , CAL.RECV_TEXT AS RECV_TEXT /* 세부입력 */ , CAL.CALL_NUM AS CALL_NUM /* 연락가능연락처 */ , CAL.ETC_MEMO AS ETC_MEMO /* 기타사항 */ , CAL.SCAN_ID AS ORG_SCAN_ID /* 생성된 스캔ID */ FROM NMCP_CUST_REQUEST_MST@DL_MCP SEL ,NMCP_CUST_REQUEST_CALL_LIST@DL_MCP CAL ,MSP_JUO_SUB_INFO SUB ,MSP_REQUEST_DTL DTL WHERE SEL.CUST_REQ_SEQ = CAL.CUST_REQ_SEQ AND SEL.CONTRACT_NUM = SUB.CONTRACT_NUM(+) AND SUB.CONTRACT_NUM = DTL.CONTRACT_NUM(+)
AND TO_CHAR(SEL.SYS_RDATE, 'YYYYMMDDHH24MISS') BETWEEN #{srchStrtDt} || '000000' AND #{srchEndDt} || '235959'
AND (SEL.CONTRACT_NUM = #{searchName} OR SEL.CONTRACT_NUM = (SELECT DISTINCT CONTRACT_NUM FROM MSP_JUO_SUB_INFO_HIST WHERE SVC_CNTR_NO = #{searchName}))
AND SEL.MOBILE_NO = #{searchName}
AND CAL.PROC_CD = #{successYn}
ORDER BY SEL.SYS_RDATE DESC

/* StatsMgmtMapper.getCallListExcel */ SELECT SEL.CUST_REQ_SEQ AS CUST_REQ_SEQ /* 시퀀스 */ , SEL.CONTRACT_NUM AS SVC_CONT_ID /* 계약번호 */ , SEL.CONTRACT_NUM AS CONTRACT_NUM /* 계약번호 */ , SUB.ON_OFF_TYPE AS ON_OFF_TYPE /* 모집경로 */ , (SELECT COUNT(*) FROM EMV_SCAN_FILE@DL_MCP WHERE SCAN_ID = SUB.SCAN_ID ) AS SCAN_FILE_CNT /* 파일건수 */ , SUB.SCAN_ID AS SCAN_ID /* 스캔ID */ , DTL.RES_NO AS RES_NO /* 예약번호 */ , SEL.CSTMR_NAME AS SUB_LINK_NAME /* 고객명 */ , TO_CHAR(TO_DATE(SUB.LST_COM_ACTV_DATE,'YYYYMMDD'), 'YYYY-MM-DD') AS LST_COM_ACTV_DATE /* 개통일 */ , SEL.MOBILE_NO AS CTN /* 전화번호 */ , FN_GET_AGE_JAVA(CRYPTO_AES256.DEC_AES(SUB.USER_SSN)) AS AGE /* 나이 */ , CASE WHEN SUBSTR(REPLACE(CRYPTO_AES256.DEC_AES(SUB.USER_SSN), '-', ''), 7, 1) IN ('1' , '3' , '5' , '7') THEN '남자' WHEN SUBSTR(REPLACE(CRYPTO_AES256.DEC_AES(SUB.USER_SSN), '-', ''), 7, 1) IN ('2' , '4' , '6' , '8') THEN '여자' END GENDER /* 성별 */ , (SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = SUB.OPEN_AGNT_CD AND ROWNUM = 1) AS OPEN_AGNT_NM /* 개통대리점 */ , FN_GET_CODENM('RCP0007', DTL.ON_OFF_TYPE) AS ON_OFF_TYPE_NM /* 모집유형 */ , (SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'CL02' AND DTL_CD = CAL.RECV_TYPE) AS RECV_TYPE /* 수신방법 */ , (SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'CL01' AND DTL_CD = CAL.PROC_CD) AS PROC_CD_NM /* 결과 */ , CAL.PROC_CD AS PROC_CD /* 결과코드 */ , TO_CHAR(CAL.SYS_RDATE, 'YYYY-MM-DD HH24:MI:SS' ) AS SYS_RDATE /* 등록일 */ , TO_CHAR(CAL.SYS_UDATE, 'YYYY-MM-DD HH24:MI:SS' ) AS SYS_UDATE /* 수정일 */ , (SELECT USR_NM FROM CMN_USR_MST WHERE USR_ID = CAL.UPDT_ID) AS UPDT_ID /* 수정자 */ , CAL.START_DATE AS START_DATE /* 시작일자 */ , CAL.END_DATE AS END_DATE /* 종료일자 */ , CAL.CL_MEMO AS CL_MEMO /* 메모 */ , (SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'CL03' AND DTL_CD = CAL.CALL_TYPE) AS CALL_TYPE /* 열람종류 */ , CAL.TYPE_VOICE AS TYPE_VOICE /* 음성 */ , CAL.TYPE_TEXT AS TYPE_TEXT /* 문자 */ , CAL.TYPE_DATA AS TYPE_DATA /* 데이터 */ , CAL.TYPE_VOICE_TEXT AS TYPE_VOICE_TEXT /* 음성+문자 */ , CAL.TYPE_ALL AS TYPE_ALL /* 음성+문자+데이터 */ , (SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'CL04' AND DTL_CD = CAL.REQ_RSN) AS REQ_RSN /* 신청사유 */ , CAL.RECV_TEXT AS RECV_TEXT /* 세부입력 */ , CAL.CALL_NUM AS CALL_NUM /* 연락가능연락처 */ , CAL.ETC_MEMO AS ETC_MEMO /* 기타사항 */ , CAL.SCAN_ID AS ORG_SCAN_ID /* 생성된 스캔ID */ FROM NMCP_CUST_REQUEST_MST@DL_MCP SEL ,NMCP_CUST_REQUEST_CALL_LIST@DL_MCP CAL ,MSP_JUO_SUB_INFO SUB ,MSP_REQUEST_DTL DTL WHERE SEL.CUST_REQ_SEQ = CAL.CUST_REQ_SEQ AND SEL.CONTRACT_NUM = SUB.CONTRACT_NUM(+) AND SUB.CONTRACT_NUM = DTL.CONTRACT_NUM(+)
AND TO_CHAR(SEL.SYS_RDATE, 'YYYYMMDDHH24MISS') BETWEEN #{srchStrtDt} || '000000' AND #{srchEndDt} || '235959'
AND (SEL.CONTRACT_NUM = #{searchName} OR SEL.CONTRACT_NUM = (SELECT DISTINCT CONTRACT_NUM FROM MSP_JUO_SUB_INFO_HIST WHERE SVC_CNTR_NO = #{searchName}))
AND SEL.MOBILE_NO = #{searchName}
AND CAL.PROC_CD = #{successYn}
ORDER BY SEL.SYS_RDATE DESC

    	/* StatsMgmtMapper.getOldScanId */
		SELECT SCAN_ID
		  FROM MSP_JUO_SUB_INFO
		 WHERE CONTRACT_NUM = #{svcContId}

    	/* StatsMgmtMapper.getFileNum */
		SELECT MAX(FILE_NUMBER) + 1 AS fileNum
		  FROM EMV_SCAN_FILE@DL_MCP
		 WHERE SCAN_ID = #{oldScanId}

    	/* StatsMgmtMapper.getNewScanId */
		SELECT SCAN_ID
		  FROM NMCP_CUST_REQUEST_CALL_LIST@DL_MCP
		 WHERE CUST_REQ_SEQ = #{custReqSeq}

    	/* StatsMgmtMapper.getNewScanIdNm */
		SELECT SCAN_ID
		  FROM NMCP_CUST_REQUEST_NAME_CHG@DL_MCP
		 WHERE CUST_REQ_SEQ = #{custReqSeq}

mapper.insert:
    	/* StatsMgmtMapper.insertEmvFile */
		INSERT INTO EMV_SCAN_FILE@DL_MCP
	    ( FILE_ID, SCAN_ID, FILE_NUMBER, FILE_SIZE, FILE_EXT, DOC_ID, MAIN_DOC_CD, USE_YN, ORIGIN_DIR, RGST_DT, RGST_PRSN_ID )
		SELECT FILE_ID, #{oldScanId}, #{fileNum} + FILE_NUMBER, FILE_SIZE, FILE_EXT, DOC_ID, MAIN_DOC_CD, USE_YN, ORIGIN_DIR, RGST_DT, RGST_PRSN_ID
		  FROM EMV_SCAN_FILE@DL_MCP
		 WHERE SCAN_ID = #{newScanId}

mapper.update:
    	/* StatsMgmtMapper.updateProcCd */
		UPDATE NMCP_CUST_REQUEST_CALL_LIST@DL_MCP
		   SET CL_MEMO = #{clMemo}
		       , PROC_CD = #{procCd}
		       , UPDT_ID =  #{sessionUserId, jdbcType=VARCHAR}
		       , SYS_UDATE = SYSDATE
		 WHERE CUST_REQ_SEQ = #{custReqSeq}

mapper.select:
/* StatsMgmtMapper.getNameChgList */
SELECT SEL.CUST_REQ_SEQ AS CUST_REQ_SEQ /* 시퀀스 */ , SEL.CONTRACT_NUM AS SVC_CONT_ID /* 계약번호 */ , SEL.CONTRACT_NUM AS CONTRACT_NUM /* 계약번호 */ , SUB.ON_OFF_TYPE AS ON_OFF_TYPE /* 모집경로 */ , (SELECT COUNT(*) FROM EMV_SCAN_FILE@DL_MCP WHERE SCAN_ID = SUB.SCAN_ID ) AS SCAN_FILE_CNT /* 파일건수 */ , SUB.SCAN_ID AS SCAN_ID /* 스캔ID */ , CAL.SCAN_ID AS NEW_SCAN_ID /* 신규 스캔ID */ , DTL.RES_NO AS RES_NO /* 예약번호 */ , SEL.CSTMR_NAME AS SUB_LINK_NAME /* 고객명 */ , TO_CHAR(TO_DATE(SUB.LST_COM_ACTV_DATE,'YYYYMMDD'), 'YYYY-MM-DD') AS LST_COM_ACTV_DATE /* 개통일 */ , SEL.MOBILE_NO AS CTN /* 양도인전화번호 */ , CAL.CSTMR_RECEIVE_TEL_FN || CAL.CSTMR_RECEIVE_TEL_MN || CAL.CSTMR_RECEIVE_TEL_RN AS CTN_GET /* 양수인전화번호 */ , FN_GET_AGE_JAVA(CRYPTO_AES256.DEC_AES(SUB.USER_SSN)) AS AGE /* 나이 */ , CASE WHEN SUBSTR(REPLACE(CRYPTO_AES256.DEC_AES(SUB.USER_SSN), '-', ''), 7, 1) IN ('1' , '3' , '5' , '7') THEN '남자' WHEN SUBSTR(REPLACE(CRYPTO_AES256.DEC_AES(SUB.USER_SSN), '-', ''), 7, 1) IN ('2' , '4' , '6' , '8') THEN '여자' END GENDER /* 성별 */ , (SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = SUB.OPEN_AGNT_CD AND ROWNUM = 1) AS OPEN_AGNT_NM /* 개통대리점 */ , FN_GET_CODENM('RCP0007', DTL.ON_OFF_TYPE) AS ON_OFF_TYPE_NM /* 모집유형 */ , (SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'CL01' AND DTL_CD = CAL.PROC_CD) AS PROC_CD_NM /* 결과 */ , CAL.PROC_CD AS PROC_CD /* 결과코드 */ , TO_CHAR(CAL.CRET_DTTM, 'YYYY-MM-DD HH24:MI:SS' ) AS SYS_RDATE /* 등록일 */ , TO_CHAR(CAL.RVISN_DTTM, 'YYYY-MM-DD HH24:MI:SS' ) AS SYS_UDATE /* 수정일 */ , (SELECT USR_NM FROM CMN_USR_MST WHERE USR_ID = CAL.RVISN_ID) AS UPDT_ID /* 수정자 */ , CAL.MEMO AS CL_MEMO /* 메모 */ , CAL.CLAUSE_CNTR_DEL_FLAG AS CLAUSE_CNTR_DEL_FLAG /* 약관_고객정보삭제동의_양도인 */ , CAL.CLAUSE_ESS_COLLECT_FLAG AS CLAUSE_ESS_COLLECT_FLAG /* 약관_고유식별 정보수집이용동의 */ , CAL.CLAUSE_JEHU_FLAG AS CLAUSE_JEHU_FLAG /* 약관_제휴서비스를 위한 동의 */ , CAL.CLAUSE_PRI_AD_FLAG AS CLAUSE_PRI_AD_FLAG /* 약관_정보,광고 전송을 위한 개인정보이용 동의 */ , CAL.CLAUSE_PRI_COLLECT_FLAG AS CLAUSE_PRI_COLLECT_FLAG /* 약관_개인정보 수집동의 */ , CAL.CLAUSE_PRI_OFFER_FLAG AS CLAUSE_PRI_OFFER_FLAG /* 약관_개인정보 제공동의 */ , CAL.PERSONAL_INFO_COLLECT_AGREE AS PERSONAL_INFO_COLLECT_AGREE /* 약관_개인정보 수집이용 동의(혜택) */ , CAL.OTHERS_TRNS_AGREE AS OTHERS_TRNS_AGREE /* 약관_제 3자 제공 동의 */ , CAL.OTHERS_TRNS_KT_AGREE AS OTHERS_TRNS_KT_AGREE /* 약관_혜택 제공을 위한 제3자 제공 동의(KT) */ , CAL.OTHERS_AD_RECEIVE_AGREE AS OTHERS_AD_RECEIVE_AGREE /* 제3자 제공관련 광고 수신 동의 */ , CAL.CSTMR_ADDR AS CSTMR_ADDR /* 주소_양도인 */ , CAL.CSTMR_ADDR_DTL AS CSTMR_ADDR_DTL /* 상세주소_양도인 */ , (SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'STRE' AND DTL_CD = CAL.CSTMR_BILL_SEND_CODE ) AS CSTMR_BILL_SEND_CODE /* 명세서종류_양도인 */ , CAL.CSTMR_MAIL AS CSTMR_MAIL /* 이메일_양도인 */ , CAL.CSTMR_NAME AS CSTMR_NAME /* 고객명_양도인 */ , CAL.CSTMR_POST AS CSTMR_POST /* 우편번호_양도인 */ , CRYPTO_AES256.DEC_AES(CAL.REQ_ACCOUNT_NUMBER) AS REQ_ACCOUNT_NUMBER /* 계좌이체_계좌번호_양도인 */ , (SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'BNK' AND DTL_CD = CAL.REQ_BANK ) AS REQ_BANK /* 계좌이체_은행코드_양도인 */ , CAL.REQ_CARD_COMPANY AS REQ_CARD_COMPANY /* 신용카드_카드사_양도인 */ , CAL.REQ_CARD_MM AS REQ_CARD_MM /* 신용카드_유효월_양도인 */ , CRYPTO_AES256.DEC_AES(CAL.REQ_CARD_NO) AS REQ_CARD_NO /* 신용카드_번호_양도인 */ , CAL.REQ_CARD_MM || '/' || CAL.REQ_CARD_YY AS REQ_CARD_YY /* 신용카드_유효년_양도인 */ , CAL.REQ_INFO_CHG_YN AS REQ_INFO_CHG_YN /* 가입정보변경여부_양도인 */ , FN_GET_CODENM('RCP0036', CAL.REQ_PAY_TYPE) AS REQ_PAY_TYPE /* 요금납부방법_양도인 */ , CAL.SELF_ISSU_EXPR_DT AS SELF_ISSU_EXPR_DT /* 신분증인증_발급/만료일자_양도인 */ , CRYPTO_AES256.DEC_AES(CAL.SELF_ISSU_NUM) AS SELF_ISSU_NUM /* 신분증인증_발급번호_양도인 */ , (SELECT RATE_NM FROM MSP_RATE_MST WHERE RATE_CD = CAL.SOC) AS SOC /* 요금제_양도인 */ , FN_GET_CODENM('RCP2006', CAL.SELF_CERT_TYPE) AS SELF_CERT_TYPE /* 신분증유형_양도인 */ , CAL.SCAN_ID AS ORG_SCAN_ID /* 생성된 스캔ID */ , NVL((SELECT (SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = PUM.ORGN_ID AND ROWNUM = 1) FROM MSP_PARTNER_USIM_MST PUM WHERE SUB.ICC_ID = PUM.USIM_NO), 'M모바일(직영온라인)') AS USIM_ORG_NM , CAL.JEHU_PROD_TYPE /*요금제 제휴처*/ , FN_GET_CODENM('RCP2038',CAL.CSTMR_FOREIGNER_NATION) AS CSTMR_FN_NM /* 국적 */ , CAL.MCN_RES_NO , '1100011741' AS CNTPNT_SHOP_ID , (SELECT KT_ORG_ID FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = '1100011741' AND ROWNUM = 1) AS MNGM_AGNC_ID , CAL.CSTMR_TYPE , CAL.CSTMR_RECEIVE_TEL_FN , CAL.CSTMR_RECEIVE_TEL_MN , CAL.CSTMR_RECEIVE_TEL_RN , CAL.FATH_TRG_YN , CAL.CLAUSE_FATH_FLAG , CAL.FATH_TRANSAC_ID , SUBSTR(CAL.FATH_CMPLT_NTFY_DT, 1, 8) AS FATH_CMPLT_NTFY_DT , CAL.FATH_TEL_NO AS SMS_RCV_TEL_NO , CAL.MCN_STATE_CODE , FN_GET_CODENM('RCP0090', CAL.MCN_STATE_CODE) AS MCN_STATE_CODE_NM FROM NMCP_CUST_REQUEST_MST@DL_MCP SEL ,NMCP_CUST_REQUEST_NAME_CHG@DL_MCP CAL ,MSP_JUO_SUB_INFO SUB ,MSP_REQUEST_DTL DTL WHERE SEL.CUST_REQ_SEQ = CAL.CUST_REQ_SEQ AND SEL.CONTRACT_NUM = SUB.CONTRACT_NUM(+) AND SUB.CONTRACT_NUM = DTL.CONTRACT_NUM(+)
AND TO_CHAR(SEL.SYS_RDATE, 'YYYYMMDDHH24MISS') BETWEEN #{srchStrtDt} || '000000' AND #{srchEndDt} || '235959'
AND (SEL.CONTRACT_NUM = #{searchName} OR SEL.CONTRACT_NUM = (SELECT DISTINCT CONTRACT_NUM FROM MSP_JUO_SUB_INFO_HIST WHERE SVC_CNTR_NO = #{searchName}))
AND SEL.MOBILE_NO = #{searchName}
AND CAL.PROC_CD = #{successYn}
ORDER BY SEL.SYS_RDATE DESC

/* StatsMgmtMapper.getNameListExcel */ SELECT SEL.CUST_REQ_SEQ AS CUST_REQ_SEQ /* 시퀀스 */ , SEL.CONTRACT_NUM AS SVC_CONT_ID /* 계약번호 */ , SEL.CONTRACT_NUM AS CONTRACT_NUM /* 계약번호 */ , SUB.ON_OFF_TYPE AS ON_OFF_TYPE /* 모집경로 */ , (SELECT COUNT(*) FROM EMV_SCAN_FILE@DL_MCP WHERE SCAN_ID = SUB.SCAN_ID ) AS SCAN_FILE_CNT /* 파일건수 */ , SUB.SCAN_ID AS SCAN_ID /* 스캔ID */ , CAL.SCAN_ID AS NEW_SCAN_ID /* 신규 스캔ID */ , DTL.RES_NO AS RES_NO /* 예약번호 */ , SEL.CSTMR_NAME AS SUB_LINK_NAME /* 고객명 */ , TO_CHAR(TO_DATE(SUB.LST_COM_ACTV_DATE,'YYYYMMDD'), 'YYYY-MM-DD') AS LST_COM_ACTV_DATE /* 개통일 */ , SEL.MOBILE_NO AS CTN /* 양도인전화번호 */ , CAL.CSTMR_RECEIVE_TEL_FN || CAL.CSTMR_RECEIVE_TEL_MN || CAL.CSTMR_RECEIVE_TEL_RN AS CTN_GET /* 양수인전화번호 */ , FN_GET_AGE_JAVA(CRYPTO_AES256.DEC_AES(SUB.USER_SSN)) AS AGE /* 나이 */ , CASE WHEN SUBSTR(REPLACE(CRYPTO_AES256.DEC_AES(SUB.USER_SSN), '-', ''), 7, 1) IN ('1' , '3' , '5' , '7') THEN '남자' WHEN SUBSTR(REPLACE(CRYPTO_AES256.DEC_AES(SUB.USER_SSN), '-', ''), 7, 1) IN ('2' , '4' , '6' , '8') THEN '여자' END GENDER /* 성별 */ , (SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = SUB.OPEN_AGNT_CD AND ROWNUM = 1) AS OPEN_AGNT_NM /* 개통대리점 */ , FN_GET_CODENM('RCP0007', DTL.ON_OFF_TYPE) AS ON_OFF_TYPE_NM /* 모집유형 */ , (SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'CL01' AND DTL_CD = CAL.PROC_CD) AS PROC_CD_NM /* 결과 */ , CAL.PROC_CD AS PROC_CD /* 결과코드 */ , TO_CHAR(CAL.CRET_DTTM, 'YYYY-MM-DD HH24:MI:SS' ) AS SYS_RDATE /* 등록일 */ , TO_CHAR(CAL.RVISN_DTTM, 'YYYY-MM-DD HH24:MI:SS' ) AS SYS_UDATE /* 수정일 */ , (SELECT USR_NM FROM CMN_USR_MST WHERE USR_ID = CAL.RVISN_ID) AS UPDT_ID /* 수정자 */ , CAL.MEMO AS CL_MEMO /* 메모 */ , CAL.CLAUSE_CNTR_DEL_FLAG AS CLAUSE_CNTR_DEL_FLAG /* 약관_고객정보삭제동의_양도인 */ , CAL.CLAUSE_ESS_COLLECT_FLAG AS CLAUSE_ESS_COLLECT_FLAG /* 약관_고유식별 정보수집이용동의 */ , CAL.CLAUSE_JEHU_FLAG AS CLAUSE_JEHU_FLAG /* 약관_제휴서비스를 위한 동의 */ , CAL.CLAUSE_PRI_AD_FLAG AS CLAUSE_PRI_AD_FLAG /* 약관_정보,광고 전송을 위한 개인정보이용 동의 */ , CAL.CLAUSE_PRI_COLLECT_FLAG AS CLAUSE_PRI_COLLECT_FLAG /* 약관_개인정보 수집동의 */ , CAL.CLAUSE_PRI_OFFER_FLAG AS CLAUSE_PRI_OFFER_FLAG /* 약관_개인정보 제공동의 */ , CAL.PERSONAL_INFO_COLLECT_AGREE AS PERSONAL_INFO_COLLECT_AGREE /* 약관_개인정보 수집이용 동의(혜택) */ , CAL.OTHERS_TRNS_AGREE AS OTHERS_TRNS_AGREE /* 약관_제 3자 제공 동의 */ , CAL.OTHERS_TRNS_KT_AGREE AS OTHERS_TRNS_KT_AGREE /* 약관_혜택 제공을 위한 제3자 제공 동의(KT) */ , CAL.OTHERS_AD_RECEIVE_AGREE AS OTHERS_AD_RECEIVE_AGREE /* 제3자 제공관련 광고 수신 동의 */ , CAL.CSTMR_ADDR AS CSTMR_ADDR /* 주소_양도인 */ , CAL.CSTMR_ADDR_DTL AS CSTMR_ADDR_DTL /* 상세주소_양도인 */ , (SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'STRE' AND DTL_CD = CAL.CSTMR_BILL_SEND_CODE ) AS CSTMR_BILL_SEND_CODE /* 명세서종류_양도인 */ , CAL.CSTMR_MAIL AS CSTMR_MAIL /* 이메일_양도인 */ , CAL.CSTMR_NAME AS CSTMR_NAME /* 고객명_양도인 */ , CAL.CSTMR_POST AS CSTMR_POST /* 우편번호_양도인 */ , CRYPTO_AES256.DEC_AES(CAL.REQ_ACCOUNT_NUMBER) AS REQ_ACCOUNT_NUMBER /* 계좌이체_계좌번호_양도인 */ , (SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'BNK' AND DTL_CD = CAL.REQ_BANK ) AS REQ_BANK /* 계좌이체_은행코드_양도인 */ , CAL.REQ_CARD_COMPANY AS REQ_CARD_COMPANY /* 신용카드_카드사_양도인 */ , CAL.REQ_CARD_MM AS REQ_CARD_MM /* 신용카드_유효월_양도인 */ , CRYPTO_AES256.DEC_AES(CAL.REQ_CARD_NO) AS REQ_CARD_NO /* 신용카드_번호_양도인 */ , CAL.REQ_CARD_MM || '/' || CAL.REQ_CARD_YY AS REQ_CARD_YY /* 신용카드_유효년_양도인 */ , CAL.REQ_INFO_CHG_YN AS REQ_INFO_CHG_YN /* 가입정보변경여부_양도인 */ , FN_GET_CODENM('RCP0036', CAL.REQ_PAY_TYPE) AS REQ_PAY_TYPE /* 요금납부방법_양도인 */ , CAL.SELF_ISSU_EXPR_DT AS SELF_ISSU_EXPR_DT /* 신분증인증_발급/만료일자_양도인 */ , CRYPTO_AES256.DEC_AES(CAL.SELF_ISSU_NUM) AS SELF_ISSU_NUM /* 신분증인증_발급번호_양도인 */ , (SELECT RATE_NM FROM MSP_RATE_MST WHERE RATE_CD = CAL.SOC) AS SOC /* 요금제_양도인 */ , FN_GET_CODENM('RCP2006', CAL.SELF_CERT_TYPE) AS SELF_CERT_TYPE /* 신분증유형_양도인 */ , NVL((SELECT (SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = PUM.ORGN_ID AND ROWNUM = 1) FROM MSP_PARTNER_USIM_MST PUM WHERE SUB.ICC_ID = PUM.USIM_NO), 'M모바일(직영온라인)') AS USIM_ORG_NM , (SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'JehuProdType' AND DTL_CD = CAL.JEHU_PROD_TYPE) AS JEHU_PROD_TYPE /*요금제 제휴처*/ , FN_GET_CODENM('RCP0090', CAL.MCN_STATE_CODE) AS MCN_STATE_CODE , CAL.MCN_RES_NO FROM NMCP_CUST_REQUEST_MST@DL_MCP SEL ,NMCP_CUST_REQUEST_NAME_CHG@DL_MCP CAL ,MSP_JUO_SUB_INFO SUB ,MSP_REQUEST_DTL DTL WHERE SEL.CUST_REQ_SEQ = CAL.CUST_REQ_SEQ AND SEL.CONTRACT_NUM = SUB.CONTRACT_NUM(+) AND SUB.CONTRACT_NUM = DTL.CONTRACT_NUM(+)
AND TO_CHAR(SEL.SYS_RDATE, 'YYYYMMDDHH24MISS') BETWEEN #{srchStrtDt} || '000000' AND #{srchEndDt} || '235959'
AND (SEL.CONTRACT_NUM = #{searchName} OR SEL.CONTRACT_NUM = (SELECT DISTINCT CONTRACT_NUM FROM MSP_JUO_SUB_INFO_HIST WHERE SVC_CNTR_NO = #{searchName}))
AND SEL.MOBILE_NO = #{searchName}
AND CAL.PROC_CD = #{successYn}
ORDER BY SEL.SYS_RDATE DESC

