/* StatsMgmtMapper.getNameChgStateList */
SELECT A.CONTRACT_NUM , A.SVC_CNTR_NO , FN_GET_CODENM('RCP0037',A.SUB_STATUS) AS SUB_STATUS , A.SUBSCRIBER_NO AS CTN , A.SUB_LINK_NAME , FN_GET_AGE_JAVA(CRYPTO_AES256.DEC_AES(A.USER_SSN)) AS AGE , TO_CHAR(TO_DATE(A.LST_COM_ACTV_DATE, 'YYYYMMDD' ), 'YYYY-MM-DD') AS LST_COM_ACTV_DATE , FN_GET_ORGNM(A.OPEN_AGNT_CD) AS OPEN_AGNT_CD , ( SELECT SUBSTR(MIN(EVNT_CHANGE_DATE),0,8) FROM MSP_JUO_SUB_INFO_HIST WHERE EVNT_CD = 'MCN' AND CONTRACT_NUM = A.CONTRACT_NUM) AS FST_CHANGE_DATE , B.EVNT_CHANGE_DATE AS LST_CHANGE_DATE , REQ.MINOR_AGENT_NAME , REQ.MINOR_AGENT_TEL , A.LGL_AGNT_NM , A.LGL_AGNT_NO , A.SCAN_ID , REQ.RES_NO FROM MSP_JUO_SUB_INFO A, MSP_REQUEST_DTL REQ , ( SELECT CONTRACT_NUM , SUBSTR(MAX(EVNT_CHANGE_DATE),0,8) EVNT_CHANGE_DATE FROM MSP_JUO_SUB_INFO_HIST WHERE EVNT_CD = 'MCN'
AND SUBSTR(EVNT_CHANGE_DATE,0,8) BETWEEN #{srchStrtDt} AND #{srchEndDt}
GROUP BY CONTRACT_NUM ) B WHERE 1=1 AND A.SUB_STATUS <> 'C'
AND FN_GET_AGE_JAVA(CRYPTO_AES256.DEC_AES(A.USER_SSN)) > 0 AND 19 > FN_GET_AGE_JAVA(CRYPTO_AES256.DEC_AES(A.USER_SSN))
AND REQ.CSTMR_TYPE <> 'JP' AND A.CONTRACT_NUM = B.CONTRACT_NUM AND A.CONTRACT_NUM = REQ.CONTRACT_NUM
AND B.EVNT_CHANGE_DATE BETWEEN #{srchStrtDt} AND #{srchEndDt}
AND (A.CONTRACT_NUM = #{searchName} OR A.CONTRACT_NUM = (SELECT DISTINCT CONTRACT_NUM FROM MSP_JUO_SUB_INFO_HIST WHERE SVC_CNTR_NO = #{searchName}))
AND A.SUBSCRIBER_NO = #{searchName}
ORDER BY A.LST_COM_ACTV_DATE DESC

