AND (SEL.CONTRACT_NUM = #{searchName} OR SEL.CONTRACT_NUM = (SELECT DISTINCT CONTRACT_NUM FROM MSP_JUO_SUB_INFO_HIST WHERE SVC_CNTR_NO = #{searchName}))
AND SEL.MOBILE_NO = #{searchName}
ORDER BY SEL.SYS_RDATE DESC

/* StatsMgmtMapper.getReqUsimPukListExcel */ SELECT SEL.CUST_REQ_SEQ AS CUST_REQ_SEQ /* 시퀀스 */ , SEL.CONTRACT_NUM AS SVC_CONT_ID /* 계약번호 */ , SEL.CONTRACT_NUM AS CONTRACT_NUM /* 계약번호 */ , SUB.ON_OFF_TYPE AS ON_OFF_TYPE /* 모집경로 */ , DTL.RES_NO AS RES_NO /* 예약번호 */ , SEL.CSTMR_NAME AS SUB_LINK_NAME /* 고객명 */ , TO_CHAR(TO_DATE(SUB.LST_COM_ACTV_DATE,'YYYYMMDD'), 'YYYY-MM-DD') AS LST_COM_ACTV_DATE /* 개통일 */ , SEL.MOBILE_NO AS CTN /* 전화번호 */ , FN_GET_AGE_JAVA(CRYPTO_AES256.DEC_AES(SUB.USER_SSN)) AS AGE /* 나이 */ , CASE WHEN SUBSTR(REPLACE(CRYPTO_AES256.DEC_AES(SUB.USER_SSN), '-', ''), 7, 1) IN ('1' , '3' , '5' , '7') THEN '남자' WHEN SUBSTR(REPLACE(CRYPTO_AES256.DEC_AES(SUB.USER_SSN), '-', ''), 7, 1) IN ('2' , '4' , '6' , '8') THEN '여자' END GENDER /* 성별 */ , (SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = SUB.OPEN_AGNT_CD AND ROWNUM = 1) AS OPEN_AGNT_NM /* 개통대리점 */ , FN_GET_CODENM('RCP0007', DTL.ON_OFF_TYPE) AS ON_OFF_TYPE_NM /* 모집유형 */ , NVL((SELECT (SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = PUM.ORGN_ID AND ROWNUM = 1) FROM MSP_PARTNER_USIM_MST PUM WHERE SUB.ICC_ID = PUM.USIM_NO), 'M모바일(직영온라인)') AS USIM_ORG_NM /* 유심접점 */ , TO_CHAR(SEL.SYS_RDATE, 'YYYY-MM-DD HH24:MI:SS' ) AS SYS_RDATE /* 등록일시 */ FROM NMCP_CUST_REQUEST_MST@DL_MCP SEL ,MSP_JUO_SUB_INFO SUB ,MSP_REQUEST_DTL DTL WHERE 1 = 1 AND SEL.REQ_TYPE = 'UP' AND SEL.CONTRACT_NUM = SUB.CONTRACT_NUM(+) AND SUB.CONTRACT_NUM = DTL.CONTRACT_NUM(+)
AND TO_CHAR(SEL.SYS_RDATE, 'YYYYMMDDHH24MISS') BETWEEN #{srchStrtDt} || '000000' AND #{srchEndDt} || '235959'
AND (SEL.CONTRACT_NUM = #{searchName} OR SEL.CONTRACT_NUM = (SELECT DISTINCT CONTRACT_NUM FROM MSP_JUO_SUB_INFO_HIST WHERE SVC_CNTR_NO = #{searchName}))
AND SEL.MOBILE_NO = #{searchName}
ORDER BY SEL.SYS_RDATE DESC

/* StatsMgmtMapper.getOmdRegList */
SELECT TO_CHAR(SYS_RDATE, 'YYYYMMDDHH24MISS') AS SYS_RDATE , REQ_MODEL_NAME , EVNT_CD , REQ_PHONE_SN , RSLT_CD , RSLT_MSG , RSLT_YN , DECODE(RSLT_YN,'Y','성공','N','실패',RSLT_YN) AS RSLT_NM , IMEI1 , IMEI2 , EID FROM MCP_UPLOAD_PHONE_INFO@DL_MCP WHERE EVNT_CD IN ('Y14', 'Y15')
AND TO_CHAR(SYS_RDATE, 'YYYYMMDDHH24MISS') BETWEEN #{srchStrtDt} || '000000' AND #{srchEndDt} || '235959'
AND RSLT_YN = #{successYn}
AND (IMEI1 = #{searchName} OR IMEI2 = #{searchName})
AND EID = #{searchName}
ORDER BY SYS_RDATE DESC

/* StatsMgmtMapper.getOmdRegListExcel */ SELECT TO_CHAR(SYS_RDATE, 'YYYY-MM-DD HH24:MI:SS') AS SYS_RDATE , REQ_MODEL_NAME , EVNT_CD , REQ_PHONE_SN , RSLT_CD , RSLT_MSG , RSLT_YN , DECODE(RSLT_YN,'Y','성공','N','실패',RSLT_YN) AS RSLT_NM , IMEI1 , IMEI2 , EID FROM MCP_UPLOAD_PHONE_INFO@DL_MCP WHERE EVNT_CD IN ('Y14', 'Y15')
AND TO_CHAR(SYS_RDATE, 'YYYYMMDDHH24MISS') BETWEEN #{srchStrtDt} || '000000' AND #{srchEndDt} || '235959'
AND RSLT_YN = #{successYn}
AND (IMEI1 = #{searchName} OR IMEI2 = #{searchName})
AND EID = #{searchName}
ORDER BY SYS_RDATE DESC

/* StatsMgmtMapper.getOwnPhoNumReqListExcel */ SELECT AA.SYS_RDATE , AA.ONLINE_AUTH_TYPE_NM , AA.CSTMR_NAME , AA.BIRTH , AA.GENDER , (SELECT COUNT(*) FROM MSP_JUO_SUB_INFO WHERE CUSTOMER_ID = AA.CUSTOMER_ID AND SUB_STATUS NOT IN ('C')) AS LINE_CNT FROM ( SELECT TO_CHAR(A.SYS_RDATE,'YYYY-MM-DD HH24:MM:SS') AS SYS_RDATE , A.ONLINE_AUTH_TYPE , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'RCP2001' AND CD_VAL = A.ONLINE_AUTH_TYPE AND USG_YN = 'Y') AS ONLINE_AUTH_TYPE_NM , A.CSTMR_NAME , SUBSTR(CRYPTO_AES256.DEC_AES(A.CSTMR_NATIVE_RRN),1,6) AS BIRTH , SUBSTR(CRYPTO_AES256.DEC_AES(A.CSTMR_NATIVE_RRN),7,1) AS GENDER , ( SELECT CUS.CUSTOMER_ID FROM ( SELECT CUSTOMER_ID , CUSTOMER_LINK_NAME , CUSTOMER_SSN , RANK() OVER(PARTITION BY CUSTOMER_SSN, CUSTOMER_LINK_NAME ORDER BY EVNT_TRTM_DT DESC) CNT FROM MSP_JUO_CUS_INFO ) CUS WHERE CUS.CUSTOMER_LINK_NAME = A.CSTMR_NAME AND CUS.CUSTOMER_SSN = A.CSTMR_NATIVE_RRN AND CUS.CNT = 1 ) AS CUSTOMER_ID FROM NMCP_OWN_PHO_NUM_HST@DL_MCP A WHERE TO_CHAR(A.SYS_RDATE, 'YYYYMMDDHH24MISS') BETWEEN #{srchStrtDt} || '000000' AND #{srchEndDt} || '235959'
AND A.CSTMR_NAME LIKE '%' || #{searchName} || '%'
ORDER BY A.SYS_RDATE DESC ) AA

/* StatsMgmtMapper.getCallQualityAsList */
SELECT CQA.REQ_SEQ AS REQ_SEQ /* 시퀀스 */ , CQA.CONTRACT_NUM AS CONTRACT_NUM /* 계약번호 */ , CQA.CSTMR_NAME AS CSTMR_NAME /* 고객명 */ , CQA.MOBILE_NO AS MOBILE_NO /* 전화번호 */ , TO_CHAR(CQA.REG_DT,'YYYY-MM-DD HH24:MI:SS') AS REG_DT /* 신청일자 */ , TO_CHAR(TO_DATE(SUB.LST_COM_ACTV_DATE,'YYYYMMDD'), 'YYYY-MM-DD') AS LST_COM_ACTV_DATE /* 개통일자 */ , FN_GET_ORGNM(SUB.OPEN_AGNT_CD) AS OPEN_AGNT_NM /* 개통대리점 */ , CQA.REG_NM AS REG_NM /* 신청자 */ , CQA.REG_MOBILE_NO AS REG_MOBILE_NO /* 신청자연락처 */ , RTRIM(DECODE(CQA.ERROR_VOICE, 'Y', '통화품질불량,','') || DECODE(CQA.ERROR_CALL, 'Y', '통화 수/발신불가,','') || DECODE(CQA.ERROR_SMS, 'Y', '문자 수/발신불가,','') || DECODE(CQA.ERROR_WIFI, 'Y', 'WIFI이용불가,','') || DECODE(CQA.ERROR_DATA, 'Y', '무선데이터이용불가,','') , ',') AS ERROR_CD /* 증상 */ , TO_CHAR(TO_DATE(CQA.ERROR_START_DATE,'YYYYMMDD'), 'YYYY-MM-DD') || ' ~ ' || TO_CHAR(TO_DATE(CQA.ERROR_END_DATE,'YYYYMMDD'), 'YYYY-MM-DD') AS ERROR_DATE /* 증상 발생기간 */ , DECODE(CQA.ERROR_TYPE_CD,'01','일시현상','02','지속현상') AS ERROR_TYPE_CD /* 발생현상 */ , DECODE(CQA.ERROR_LOC_TYPE_CD,'01','지역무관','02','특정지역') AS ERROR_LOC_TYPE_NM /* 증상발생지(지역무관,특정지역) */ , CQA.ERROR_LOC_TYPE_CD AS ERROR_LOC_TYPE_CD /* 증상발생코드(01:지역무관, 02:특정지역)*/ , CQA.COUNSEL_DETAIL AS COUNSEL_DETAIL /* 상담내용 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'RCP9035' AND CD_VAL = CQA.COUNSEL_RSLT_CD ) AS COUNSEL_RSLT_CD_NM /* 상담결과 (R:접수, C:처리, B:반려) */ , CQA.COUNSEL_RSLT_CD AS COUNSEL_RSLT_CD /* 상담결과코드 (R:접수, C:처리, B:반려) */ , CQA.CSTMR_ADDR || ' ' || CQA.CSTMR_ADDR_DTL AS CSTMR_ADDR /* 우편번호를 제외한 주소지 */ FROM MCP_CALL_QUALITY_AS_LIST@DL_MCP CQA ,MSP_JUO_SUB_INFO SUB WHERE CQA.CONTRACT_NUM = SUB.CONTRACT_NUM
AND TO_CHAR(CQA.REG_DT, 'YYYYMMDDHH24MISS') BETWEEN #{srchStrtDt} || '000000' AND #{srchEndDt} || '235959'
AND (CQA.CONTRACT_NUM = #{searchName} OR CQA.CONTRACT_NUM = (SELECT DISTINCT CONTRACT_NUM FROM MSP_JUO_SUB_INFO_HIST WHERE SVC_CNTR_NO = #{searchName}))
AND CQA.MOBILE_NO = #{searchName}
AND CQA.COUNSEL_RSLT_CD = #{successYn}
AND DECODE(#{errorCd}, 'errorVoice', NVL(CQA.ERROR_VOICE, 'Y'), 'errorCall', NVL(CQA.ERROR_CALL, 'Y'), 'errorSms', NVL(CQA.ERROR_SMS, 'Y'), 'errorWifi', NVL(CQA.ERROR_WIFI, 'Y'), 'errorData', NVL(CQA.ERROR_DATA, 'Y'), 'N') = 'Y'
ORDER BY CQA.REG_DT DESC

