/* StatsMgmtMapper.getCallQualityAsListExcel */
SELECT CQA.REQ_SEQ AS REQ_SEQ /* 시퀀스 */ , CQA.CONTRACT_NUM AS CONTRACT_NUM /* 계약번호 */ , CQA.CSTMR_NAME AS CSTMR_NAME /* 고객명 */ , CQA.MOBILE_NO AS MOBILE_NO /* 전화번호 */ , TO_CHAR(CQA.REG_DT,'YYYY-MM-DD HH24:MI:SS') AS REG_DT /* 신청일자 */ , TO_CHAR(TO_DATE(SUB.LST_COM_ACTV_DATE,'YYYYMMDD'), 'YYYY-MM-DD') AS LST_COM_ACTV_DATE /* 개통일자 */ , FN_GET_ORGNM(SUB.OPEN_AGNT_CD) AS OPEN_AGNT_NM /* 개통대리점 */ , CQA.REG_NM AS REG_NM /* 신청자 */ , CQA.REG_MOBILE_NO AS REG_MOBILE_NO /* 신청자연락처 */ , RTRIM(DECODE(CQA.ERROR_VOICE, 'Y', '통화품질불량,','') || DECODE(CQA.ERROR_CALL, 'Y', '통화 수/발신불가,','') || DECODE(CQA.ERROR_SMS, 'Y', '문자 수/발신불가,','') || DECODE(CQA.ERROR_WIFI, 'Y', 'WIFI이용불가,','') || DECODE(CQA.ERROR_DATA, 'Y', '무선데이터이용불가,','') , ',') AS ERROR_CD /* 증상 */ , TO_CHAR(TO_DATE(CQA.ERROR_START_DATE,'YYYYMMDD'), 'YYYY-MM-DD') || ' ~ ' || TO_CHAR(TO_DATE(CQA.ERROR_END_DATE,'YYYYMMDD'), 'YYYY-MM-DD') AS ERROR_DATE /* 증상 발생기간 */ , DECODE(CQA.ERROR_TYPE_CD,'01','일시현상','02','지속현상') AS ERROR_TYPE_CD /* 발생현상 */ , DECODE(CQA.ERROR_LOC_TYPE_CD,'01','지역무관','02','특정지역') AS ERROR_LOC_TYPE_NM /* 증상발생지(지역무관,특정지역) */ , CQA.ERROR_LOC_TYPE_CD AS ERROR_LOC_TYPE_CD /* 증상발생코드(01:지역무관, 02:특정지역)*/ , CQA.COUNSEL_DETAIL AS COUNSEL_DETAIL /* 상담내용 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'RCP9035' AND CD_VAL = CQA.COUNSEL_RSLT_CD ) AS COUNSEL_RSLT_CD_NM /* 상담결과 (R:접수, C:처리, B:반려) */ , CQA.COUNSEL_RSLT_CD AS COUNSEL_RSLT_CD /* 상담결과코드 (R:접수, C:처리, B:반려) */ , CQA.CSTMR_ADDR || ' ' || CQA.CSTMR_ADDR_DTL AS CSTMR_ADDR /* 우편번호를 제외한 주소지 */ FROM MCP_CALL_QUALITY_AS_LIST@DL_MCP CQA ,MSP_JUO_SUB_INFO SUB WHERE CQA.CONTRACT_NUM = SUB.CONTRACT_NUM
AND TO_CHAR(CQA.REG_DT, 'YYYYMMDDHH24MISS') BETWEEN #{srchStrtDt} || '000000' AND #{srchEndDt} || '235959'
AND (CQA.CONTRACT_NUM = #{searchName} OR CQA.CONTRACT_NUM = (SELECT DISTINCT CONTRACT_NUM FROM MSP_JUO_SUB_INFO_HIST WHERE SVC_CNTR_NO = #{searchName}))
AND CQA.MOBILE_NO = #{searchName}
AND CQA.COUNSEL_RSLT_CD = #{successYn}
AND DECODE(#{errorCd}, 'errorVoice', NVL(CQA.ERROR_VOICE, 'Y'), 'errorCall', NVL(CQA.ERROR_CALL, 'Y'), 'errorSms', NVL(CQA.ERROR_SMS, 'Y'), 'errorWifi', NVL(CQA.ERROR_WIFI, 'Y'), 'errorData', NVL(CQA.ERROR_DATA, 'Y'), 'N') = 'Y'
ORDER BY CQA.REG_DT DESC

/*StatsMgmtMapper.getCsResInfoList*/
SELECT RES.CS_RES_DT /*예약상담일시*/ ,RES.CS_RES_TM /*예약상담시간대 코드*/ ,RES.CS_RES_TM_NM /*예약상담시간대*/ ,RES.PER_CNT /*허용인원*/ ,RES.RES_CNT /*예약고객수*/ ,RES.PER_CNT-RES.RES_CNT AS REMAIN_CNT /*예약가능고객수*/ ,(CASE WHEN RES.PER_CNT-RES.RES_CNT <= 0 THEN '종결' WHEN TO_DATE((RES.CS_RES_DT || '00:00:00'),'YYYYMMDDHH24:MI:SS') > SYSDATE THEN '예약가능' ELSE '종결' END) AS RES_STAT /*상태값(예약가능,종결)*/ ,RES.COM_CNT /*상담완료고객수*/ ,RES.RES_CNT-RES.COM_CNT AS UNCOM_CNT /*상담미완료고객수*/ ,(CASE WHEN RES.RES_CNT-RES.COM_CNT <= 0 THEN '완료' WHEN TO_DATE((RES.CS_RES_DT || RES.DEADLINE || ':00'),'YYYYMMDDHH24:MI:SS') > SYSDATE THEN '진행중' ELSE '미처리' END) AS CS_STAT /*처리상태(종결,진행중,미처리)*/ FROM ( SELECT CR.CS_RES_DT ,CR.CS_RES_TM ,FN_GET_CODENM('VOC0024', CR.CS_RES_TM) AS CS_RES_TM_NM ,SUBSTR(FN_GET_CODENM('VOC0024', CR.CS_RES_TM),7,5) AS DEADLINE ,CR.PER_CNT ,(SELECT COUNT(CS_RES_SEQ) FROM MSP_CS_RES_CSTMR CRC WHERE CRC.CS_RES_DT= CR.CS_RES_DT AND CRC.CS_RES_TM= CR.CS_RES_TM AND NVL(DEL_YN,'N') != 'Y') AS RES_CNT ,(SELECT COUNT(CS_RES_SEQ) FROM MSP_CS_RES_CSTMR CRC WHERE CRC.CS_RES_DT= CR.CS_RES_DT AND CRC.CS_RES_TM= CR.CS_RES_TM AND NVL(DEL_YN,'N') != 'Y' AND CS_STAT_CD= 'COM') as COM_CNT FROM MSP_CS_RES CR WHERE 1=1
AND CR.CS_RES_DT BETWEEN #{srchStrtDt} AND #{srchEndDt}
AND CR.CS_RES_DT= #{csResDt} AND CR.CS_RES_TM= #{csResTm}
) RES ORDER BY CS_RES_DT DESC, CS_RES_TM ASC

mapper.insert:
/*StatsMgmtMapper.mergeCsResPerCntByDt*/
MERGE INTO MSP_CS_RES
	USING DUAL ON (CS_RES_DT = #{csResDt} AND CS_RES_TM= UPPER(#{csResTm}))
	WHEN MATCHED THEN
		UPDATE SET
			PER_CNT= #{perCnt}
		   ,RVISN_ID = #{userId}
		   ,RVISN_DTTM = SYSDATE
	WHEN NOT MATCHED THEN
		INSERT (
			CS_RES_DT
		   ,CS_RES_TM
		   ,PER_CNT
		   ,REGST_ID
		   ,REGST_DTTM
		)VALUES(
		 	#{csResDt}
		   ,UPPER(#{csResTm})
		   ,#{perCnt}
		   ,#{userId}
		   ,SYSDATE
		)

mapper.select:
/*StatsMgmtMapper.getPrmtAutoAddList*/
SELECT A.PRC_MST_SEQ ,A.PRMT_ID ,A.CONTRACT_NUM ,(SELECT PRMT_NM FROM MSP_DIS_MST WHERE PRMT_ID = A.PRMT_ID) AS PRMT_NM ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID ='CMN0091' AND CD_VAL = A.EVNT_CD) AS CD_DSC ,(SELECT SUB_LINK_NAME FROM MSP_JUO_SUB_INFO WHERE CONTRACT_NUM=A.CONTRACT_NUM) AS CUST_NM ,A.EFFECTIVE_DATE AS EFFECTIVE_DATE ,A.SUCC_YN ,A.FNL_SUCC_YN ,DECODE(A.SUCC_YN, 'Y' , '성공' , '실패') AS SUCC_YN_NM ,DECODE(A.FNL_SUCC_YN, 'Y' , '성공' , '') AS FNL_SUCC_YN_NM ,TO_CHAR(A.REGST_DTTM, 'YYYYMMDDHH24MISS') AS REGST_DTTM ,A.PROC_YN ,TO_CHAR(A.PROC_DATE, 'YYYYMMDDHH24MISS') AS PROC_DATE ,A.PROC_ID ,NVL2(A.PROC_ID, F_GET_ADMIN_NM(A.PROC_ID), '') AS PROC_NM ,A.PROC_MEMO FROM MSP_DIS_PRC_MST A WHERE A.EFFECTIVE_DT BETWEEN #{srchStrtDt} AND #{srchEndDt}
AND A.CONTRACT_NUM = #{contractNum}
AND (A.SUCC_YN ='Y' OR A.FNL_SUCC_YN = 'Y')
AND (A.SUCC_YN ='N' AND A.FNL_SUCC_YN IS NULL)
AND A.EVNT_CD = #{evntCd}
AND A.PROC_YN = 'Y'
AND A.PROC_YN IS NULL
AND A.PRMT_AGNT_CD = #{cntpntShopId}
ORDER BY PRC_MST_SEQ DESC

