UPDATE MSP_DIS_PRC_MST
SET  PROC_YN = 'Y'
  ,PROC_DATE = SYSDATE
  ,PROC_ID = #{userId}
  ,PROC_MEMO = #{procMemo}
WHERE PRC_MST_SEQ = #{prcMstSeq}

