/*StatsMgmtMapper.getPrmtAutoAddListExcel*/ SELECT A.PRC_MST_SEQ ,A.PRMT_ID ,A.CONTRACT_NUM ,(SELECT PRMT_NM FROM MSP_DIS_MST WHERE PRMT_ID = A.PRMT_ID) AS PRMT_NM ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID ='CMN0091' AND CD_VAL = A.EVNT_CD) AS CD_DSC ,(SELECT SUB_LINK_NAME FROM MSP_JUO_SUB_INFO WHERE CONTRACT_NUM = A.CONTRACT_NUM) AS CUST_NM ,TO_CHAR(TO_DATE(A.EFFECTIVE_DATE, 'YYYYMMDDHH24MISS'), 'YYYY-MM-DD HH24:MI:SS') AS EFFECTIVE_DATE ,DECODE(A.SUCC_YN, 'Y', '성공', '실패') AS SUCC_YN ,DECODE(A.FNL_SUCC_YN, 'Y', '성공', '') AS FNL_SUCC_YN ,TO_CHAR(A.REGST_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS REGST_DTTM ,A.PROC_YN ,TO_CHAR(A.PROC_DATE, 'YYYY-MM-DD HH24:MI:SS') AS PROC_DATE ,A.PROC_ID ,NVL2(A.PROC_ID, F_GET_ADMIN_NM(A.PROC_ID), '') AS PROC_NM ,A.PROC_MEMO FROM MSP_DIS_PRC_MST A WHERE 1 = 1
AND A.EFFECTIVE_DT BETWEEN #{srchStrtDt} AND #{srchEndDt}
AND A.EFFECTIVE_DT BETWEEN TO_CHAR(SYSDATE- 7, 'YYYYMMDD') AND TO_CHAR(SYSDATE, 'YYYYMMDD')
AND A.CONTRACT_NUM = #{contractNum}
AND (A.SUCC_YN ='Y' OR A.FNL_SUCC_YN = 'Y')
AND (A.SUCC_YN ='N' AND A.FNL_SUCC_YN IS NULL)
AND A.EVNT_CD = #{evntCd}
AND A.PROC_YN = 'Y'
AND A.PROC_YN IS NULL
AND A.PRMT_AGNT_CD =#{cntpntShopId}
ORDER BY A.PRC_MST_SEQ DESC

/* StatsMgmtMapper.getCstmrSubInfo */
SELECT CUSTOMER_ID, SUBSCRIBER_NO, SVC_CNTR_NO, CONTRACT_NUM
