/*StatsMgmtMapper.getDisPrmtTrgMgmtList*/
SELECT TRG_MST_SEQ ,TRG_DTL_SEQ ,REGST_DT ,PROC_YN ,PROC_ID ,TO_CHAR(PROC_DTTM, 'YYYYMMDDHH24MISS') AS PROC_DTTM ,CONTRACT_NUM ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID ='CMN0091' AND CD_VAL = A.EVNT_CD) AS EVNT_CD ,EVNT_TRTM_NO ,EVNT_TRTM_DT ,EFFECTIVE_DATE ,REGST_ID ,TO_CHAR(REGST_DTTM, 'YYYYMMDDHH24MISS') AS REGST_DTTM FROM MSP_DIS_TRG_MST A WHERE 1=1
AND A.EFFECTIVE_DATE BETWEEN #{srchStrtDt} || '000000' AND #{srchEndDt} || '235959'
AND TO_CHAR(A.REGST_DTTM, 'YYYYMMDDHH24MISS') BETWEEN #{srchStrtDt} || '000000' AND #{srchEndDt} || '235959'
AND A.REGST_DT != SUBSTR(EFFECTIVE_DATE,1,8)
AND A.EVNT_CD = #{evntCd}
AND A.CONTRACT_NUM = #{contractNum}
AND A.PROC_YN = #{procYn}
ORDER BY A.TRG_MST_SEQ DESC

/*StatsMgmtMapper.getDisPrmtTrgMgmtListExcel*/ SELECT TRG_MST_SEQ ,TRG_DTL_SEQ ,REGST_DT ,PROC_YN ,PROC_ID ,TO_CHAR(PROC_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS PROC_DTTM ,CONTRACT_NUM ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID ='CMN0091' AND CD_VAL = A.EVNT_CD) AS EVNT_CD ,EVNT_TRTM_NO ,TO_CHAR(TO_DATE(EVNT_TRTM_DT, 'YYYYMMDDHH24MISS'),'YYYY-MM-DD HH24:MI:SS') AS EVNT_TRTM_DT ,TO_CHAR(TO_DATE(EFFECTIVE_DATE, 'YYYYMMDDHH24MISS'),'YYYY-MM-DD HH24:MI:SS') AS EFFECTIVE_DATE ,REGST_ID ,TO_CHAR(REGST_DTTM,'YYYY-MM-DD HH24:MI:SS') AS REGST_DTTM FROM MSP_DIS_TRG_MST A WHERE 1=1
AND A.EFFECTIVE_DATE BETWEEN #{srchStrtDt} || '000000' AND #{srchEndDt} || '235959'
AND TO_CHAR(A.REGST_DTTM, 'YYYYMMDDHH24MISS') BETWEEN #{srchStrtDt} || '000000' AND #{srchEndDt} || '235959'
AND A.REGST_DT != SUBSTR(EFFECTIVE_DATE,1,8)
AND A.EVNT_CD = #{evntCd}
AND A.CONTRACT_NUM = #{contractNum}
AND A.PROC_YN = #{procYn}
ORDER BY A.TRG_MST_SEQ DESC

/*StatsMgmtMapper.getDisPrmtTrgMgmtDtlPop*/
SELECT TRG_DTL_SEQ ,REGST_DT ,PROC_YN ,PROC_ID ,TO_CHAR(PROC_DTTM, 'YYYYMMDDHH24MISS') AS PROC_DTTM ,CONTRACT_NUM ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID ='CMN0091' AND CD_VAL = A.EVNT_CD) AS EVNT_CD ,EVNT_TRTM_NO ,EVNT_TRTM_DT ,EFFECTIVE_DATE ,REGST_ID ,TO_CHAR(REGST_DTTM, 'YYYYMMDDHH24MISS') AS REGST_DTTM FROM MSP_DIS_TRG_DTL A WHERE 1=1
AND A.EFFECTIVE_DATE BETWEEN #{srchStrtDt} || '000000' AND #{srchEndDt} || '235959'
AND A.REGST_DT BETWEEN #{srchStrtDt} AND #{srchEndDt}
AND A.CONTRACT_NUM = #{contractNum}
