/*StatsMgmtMapper.getDisPrmtTrgMgmtDtlPopExcel*/ SELECT TRG_DTL_SEQ ,REGST_DT ,PROC_YN ,PROC_ID ,TO_CHAR(PROC_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS PROC_DTTM ,CONTRACT_NUM ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID ='CMN0091' AND CD_VAL = A.EVNT_CD) AS EVNT_CD ,EVNT_TRTM_NO ,TO_CHAR(TO_DATE(EVNT_TRTM_DT, 'YYYYMMDDHH24MISS'), 'YYYY-MM-DD HH24:MI:SS') AS EVNT_TRTM_DT ,TO_CHAR(TO_DATE(EFFECTIVE_DATE, 'YYYYMMDDHH24MISS'), 'YYYY-MM-DD HH24:MI:SS') AS EFFECTIVE_DATE ,REGST_ID ,TO_CHAR(REGST_DTTM,'YYYY-MM-DD HH24:MI:SS') AS REGST_DTTM FROM MSP_DIS_TRG_DTL A WHERE 1=1
AND A.EFFECTIVE_DATE BETWEEN #{srchStrtDt} || '000000' AND #{srchEndDt} || '235959'
AND A.REGST_DT BETWEEN #{srchStrtDt} AND #{srchEndDt}
AND A.CONTRACT_NUM = #{contractNum}
AND A.EVNT_CD = #{evntCd}
AND A.PROC_YN = #{procYn}
ORDER BY A.TRG_DTL_SEQ DESC

/*StatsMgmtMapper.getDisPrmtDelayMst*/ SELECT A.PRC_MST_SEQ ,A.EFFECTIVE_DATE ,(SELECT PRMT_NM FROM MSP_DIS_MST WHERE PRMT_ID = A.PRMT_ID) AS PRMT_NM ,C.SUB_LINK_NAME AS CUST_NM ,A.CONTRACT_NUM ,C.SUBSCRIBER_NO AS SUBSCRIBER_NO ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID ='CMN0091' AND CD_VAL = A.EVNT_CD) AS CD_DSC ,A.PROC_YN ,TO_CHAR(A.PROC_DATE,'YYYYMMDDHH24MISS') AS PROC_DATE ,(SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = A.PRMT_AGNT_CD AND ROWNUM = 1) AS PRMT_AGNT FROM MSP_DIS_PRC_MST A, VW_DIS_PRC_DELAY B, MSP_JUO_SUB_INFO C WHERE A.PRC_MST_SEQ = B.PRC_MST_SEQ AND A.CONTRACT_NUM = C.CONTRACT_NUM AND B.EFFECTIVE_DT= #{srchStrtDt}
AND C.SUB_LINK_NAME = #{searchName}
AND A.CONTRACT_NUM = #{searchName}
AND C.SUBSCRIBER_NO = #{searchName}
AND A.EVNT_CD = #{evntCd}
AND A.PROC_YN = 'Y'
AND A.PROC_YN IS NULL
AND A.PRMT_AGNT_CD = #{cntpntShopId}
ORDER BY A.PRC_MST_SEQ DESC

/*StatsMgmtMapper.getDisPrmtDelayMstExcel*/ SELECT TO_CHAR(TO_DATE(A.EFFECTIVE_DATE, 'YYYYMMDDHH24MISS'),'YYYY-MM-DD HH24:MI:SS') AS EFFECTIVE_DATE ,(SELECT PRMT_NM FROM MSP_DIS_MST WHERE PRMT_ID = A.PRMT_ID) AS PRMT_NM ,C.SUB_LINK_NAME AS CUST_NM ,A.CONTRACT_NUM ,C.SUBSCRIBER_NO AS SUBSCRIBER_NO ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID ='CMN0091' AND CD_VAL = A.EVNT_CD) AS CD_DSC ,A.PROC_YN ,TO_CHAR(A.PROC_DATE,'YYYY-MM-DD HH24:MI:SS') AS PROC_DATE ,A.PRMT_AGNT_CD ,(SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = A.PRMT_AGNT_CD AND ROWNUM = 1) AS PRMT_AGNT FROM MSP_DIS_PRC_MST A, VW_DIS_PRC_DELAY B, MSP_JUO_SUB_INFO C WHERE A.PRC_MST_SEQ = B.PRC_MST_SEQ AND A.CONTRACT_NUM = C.CONTRACT_NUM AND B.EFFECTIVE_DT= #{srchStrtDt}
AND C.SUB_LINK_NAME = #{searchName}
AND A.CONTRACT_NUM = #{searchName}
AND C.SUBSCRIBER_NO = #{searchName}
AND A.EVNT_CD = #{evntCd}
AND A.PROC_YN = 'Y'
AND A.PROC_YN IS NULL
AND A.PRMT_AGNT_CD = #{cntpntShopId}
ORDER BY A.PRC_MST_SEQ DESC

