SELECT A.CUST_NM ,A.BIRTH_DT ,A.GENDER ,A.CTN ,A.SVC_CNTR_ID ,A.SVC_CNTR_ID AS SVC_CNTR_ID_MSK ,A.PROD_CD ,A.PROD_NM ,A.STATUS ,A.REG_DT ,A.OPEN_DT ,A.CAN_DT ,A.REG_TYPE ,A.INTERNET_ID ,A.COMB_YN ,A.CUST_ID FROM MSP_INET_INFO_MST A WHERE 1=1
AND TO_CHAR(TO_DATE(A.REG_DT,'YYYY-MM-DD'),'YYYYMMDD') BETWEEN #{srchStrtDt} AND #{srchEndDt}
AND A.STATUS = #{subStatus}
AND A.COMB_YN = #{combYn}
AND A.CUST_NM LIKE #{searchName} || '%'
AND A.CTN = #{searchName}
AND A.PROD_NM = #{searchName}
AND A.INTERNET_ID = #{searchName}
ORDER BY A.REG_DT DESC

mapper.select:
SELECT /* StatsMgmtMapper.getMcashJoinCustMgmtList */ MCASH.USERID AS USER_ID, MCASH.USERID AS MASK_USER_ID, ( SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'McashUserStatus' AND DTL_CD = MCASH.STATUS ) AS STATUS, MCASH.CONTRACT_NUM, MCASH.SVC_CNTR_NO, TO_CHAR(MCASH.REGST_DTTM, 'YYYYMMDD') AS STRT_DTTM, SUB.SUB_LINK_NAME AS CUST_NM, SUB.SUBSCRIBER_NO AS MOBILE_NO, SUBSTR(CRYPTO_AES256.DEC_AES(NVL(SUB.USER_SSN, ' ')), 1,6) AS USER_SSN, ( SELECT FN_GET_RATENM(FEA.SOC) FROM MSP_JUO_FEATURE_INFO FEA WHERE FEA.CONTRACT_NUM = MCASH.CONTRACT_NUM AND FEA.SERVICE_TYPE = 'P' AND MCASH.NEW_DTTM BETWEEN FEA.APP_START_DD AND FEA.APP_END_DATE AND ROWNUM = 1 ) AS FST_RATE_NM, DTL.LST_RATE_NM, MCASH.NEW_DTTM, DECODE(MOD(SUB.GENDER, 2), '1', '남', '0', '여') AS GENDER, DTL.OPER_TYPE_NM, FN_GET_CODENM('MSP0003', SUB.SUB_STATUS) AS SUB_STATUS_NM, FN_GET_ORGNM(SUB.OPEN_AGNT_CD) AS OPEN_AGNT_NM, NVL((SELECT (SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = PUM.ORGN_ID AND ROWNUM = 1) FROM MSP_PARTNER_USIM_MST PUM WHERE SUB.ICC_ID = PUM.USIM_NO), 'M모바일(직영온라인)') AS USIM_ORG_NM, SUB.LST_COM_ACTV_DATE AS OPEN_DT, DECODE(SUB.SUB_STATUS, 'C', SUBSTR (SUB.SUB_STATUS_DATE, 1, 8), '') AS TMNT_DT, DECODE(SUB.SUB_STATUS, 'C', FN_GET_CODENM('RCP0060', FN_GET_CANRSN(SUB.CONTRACT_NUM)), '') AS CAN_RSN, DTL.MOVE_COMPANY_NM, ( SELECT NVL((SELECT NVL(DTL_CD_NM, NP_COMM_CMPN_ID) FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'NSC' AND DTL_CD = NP_COMM_CMPN_ID), (SELECT NVL(DTL_CD_NM, NP_COMM_CMPN_ID) FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'NSC' AND EXPNSN_STR_VAL1 = NP_COMM_CMPN_ID AND USE_YN = 'Y')) FROM MDS_PORTOUT_MST MPM WHERE MPM.CONTRACT_NUM = SUB.CONTRACT_NUM ) AS CMPN_NM FROM ( SELECT USERID, STATUS, CONTRACT_NUM, SVC_CNTR_NO, STRT_DTTM, REGST_DTTM, ( SELECT TO_CHAR(MIN(REGST_DTTM), 'YYYYMMDDHH24MISS') FROM NMCP_MCASH_USER_HIST@DL_MCP WHERE CUSTOMER_ID = MUSER.CUSTOMER_ID ) AS NEW_DTTM FROM NMCP_MCASH_USER@DL_MCP MUSER) MCASH, MSP_JUO_SUB_INFO SUB, MSP_REQUEST_DTL DTL WHERE MCASH.CONTRACT_NUM = SUB.CONTRACT_NUM AND MCASH.CONTRACT_NUM = DTL.CONTRACT_NUM
AND MCASH.REGST_DTTM >= TO_DATE(#{srchStrtDt}, 'YYYYMMDD') AND MCASH.REGST_DTTM < TO_DATE(#{srchEndDt}, 'YYYYMMDD') + 1
AND MCASH.STATUS = #{subStatus}
AND MCASH.SVC_CNTR_NO = #{searchName}
AND MCASH.CONTRACT_NUM = #{searchName}
AND SUB.SUBSCRIBER_NO = #{searchName}
AND MCASH.USERID = #{searchName}
AND SUB.SUB_LINK_NAME = #{searchName}
ORDER BY MCASH.REGST_DTTM DESC

SELECT /* StatsMgmtMapper.getMcashJoinCustMgmtListExcel */ MCASH.USERID AS USER_ID, MCASH.USERID AS MASK_USER_ID, (SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'McashUserStatus' AND DTL_CD = MCASH.STATUS) AS STATUS, MCASH.CONTRACT_NUM, MCASH.SVC_CNTR_NO, TO_CHAR(MCASH.REGST_DTTM, 'YYYYMMDD') AS STRT_DTTM, SUB.SUB_LINK_NAME AS CUST_NM, SUB.SUBSCRIBER_NO AS MOBILE_NO, SUBSTR(CRYPTO_AES256.DEC_AES(NVL(SUB.USER_SSN, ' ')), 1,6) AS USER_SSN, ( SELECT FN_GET_RATENM(FEA.SOC) FROM MSP_JUO_FEATURE_INFO FEA WHERE FEA.CONTRACT_NUM = MCASH.CONTRACT_NUM AND FEA.SERVICE_TYPE = 'P' AND MCASH.NEW_DTTM BETWEEN FEA.APP_START_DD AND FEA.APP_END_DATE AND ROWNUM = 1) AS FST_RATE_NM, ( SELECT FEA.SOC FROM MSP_JUO_FEATURE_INFO FEA WHERE FEA.CONTRACT_NUM = MCASH.CONTRACT_NUM AND FEA.SERVICE_TYPE = 'P' AND MCASH.NEW_DTTM BETWEEN FEA.APP_START_DD AND FEA.APP_END_DATE AND ROWNUM = 1) AS FST_RATE_CD, DTL.LST_RATE_NM, DTL.LST_RATE_CD, MCASH.NEW_DTTM, DECODE(MOD(SUB.GENDER, 2), '1', '남', '0', '여') AS GENDER, DTL.OPER_TYPE_NM, FN_GET_CODENM('MSP0003', SUB.SUB_STATUS) AS SUB_STATUS_NM, FN_GET_ORGNM(SUB.OPEN_AGNT_CD) AS OPEN_AGNT_NM, NVL((SELECT ( SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = PUM.ORGN_ID AND ROWNUM = 1) FROM MSP_PARTNER_USIM_MST PUM WHERE SUB.ICC_ID = PUM.USIM_NO), 'M모바일(직영온라인)') AS USIM_ORG_NM, SUB.LST_COM_ACTV_DATE AS OPEN_DT, DECODE(SUB.SUB_STATUS, 'C', SUBSTR(SUB.SUB_STATUS_DATE, 1, 8), '') AS TMNT_DT, DECODE(SUB.SUB_STATUS, 'C', FN_GET_CODENM('RCP0060', FN_GET_CANRSN(SUB.CONTRACT_NUM)), '') AS CAN_RSN, DTL.MOVE_COMPANY_NM, ( SELECT NVL((SELECT NVL(DTL_CD_NM, NP_COMM_CMPN_ID) FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'NSC' AND DTL_CD = NP_COMM_CMPN_ID), (SELECT NVL(DTL_CD_NM, NP_COMM_CMPN_ID) FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'NSC' AND EXPNSN_STR_VAL1 = NP_COMM_CMPN_ID AND USE_YN = 'Y')) FROM MDS_PORTOUT_MST MPM WHERE MPM.CONTRACT_NUM = SUB.CONTRACT_NUM ) AS CMPN_NM , NVL((SELECT AGR_YN FROM MSP_MRKT_AGR_MGMT WHERE CONTRACT_NUM = SUB.CONTRACT_NUM AND END_DTTM = '99991231235959' ), 'N') AS AGR_YN FROM ( SELECT USERID, STATUS, CONTRACT_NUM, SVC_CNTR_NO, STRT_DTTM, REGST_DTTM, ( SELECT TO_CHAR(MIN(REGST_DTTM), 'YYYYMMDDHH24MISS') FROM NMCP_MCASH_USER_HIST@DL_MCP WHERE CUSTOMER_ID = MUSER.CUSTOMER_ID ) AS NEW_DTTM FROM NMCP_MCASH_USER@DL_MCP MUSER) MCASH, MSP_JUO_SUB_INFO SUB, MSP_REQUEST_DTL DTL WHERE MCASH.CONTRACT_NUM = SUB.CONTRACT_NUM AND MCASH.CONTRACT_NUM = DTL.CONTRACT_NUM
AND MCASH.REGST_DTTM >= TO_DATE(#{srchStrtDt}, 'YYYYMMDD') AND MCASH.REGST_DTTM < TO_DATE(#{srchEndDt}, 'YYYYMMDD') + 1
AND MCASH.STATUS = #{subStatus}
AND MCASH.SVC_CNTR_NO = #{searchName}
AND MCASH.CONTRACT_NUM = #{searchName}
AND SUB.SUBSCRIBER_NO = #{searchName}
AND MCASH.USERID = #{searchName}
AND SUB.SUB_LINK_NAME = #{searchName}
ORDER BY MCASH.REGST_DTTM DESC

/* StatsMgmtMapper.getAppFormSyncList */
WITH KTIS_KNOTE_SCAN_HIST_ALL AS ( SELECT ITEM_ID, REGST_DTTM,'Y' AS SUCC_YN FROM KIS_KNOTE_SCAN_HIST UNION ALL SELECT ITEM_ID, REGST_DTTM, 'N' AS SUCC_YN FROM KIS_KNOTE_SCAN_FAIL WHERE RSLT_CD != '2001' ) SELECT A.LST_COM_ACTV_DATE, TO_CHAR(TO_DATE(LST_COM_ACTV_DATE, 'YYYY-MM-DD'), 'YYYY-MM-DD') AS LST_COM_ACTV_DATE_VAL, A.CONTRACT_NUM, A.ITEM_ID, DECODE(A.SUCC_YN, 'Y', '존재', '미존재') AS SUCC_YN, DECODE(B.SUCC_YN, 'Y', '성공', 'N', '실패', '미존재') AS SUCC_RECENT_YN FROM ( SELECT SUB.LST_COM_ACTV_DATE, SUB.CONTRACT_NUM, SUB.ITEM_ID, CASE WHEN(SELECT COUNT(ITEM_ID) FROM KIS_KNOTE_SCAN_HIST WHERE ITEM_ID = SUB.ITEM_ID) > 0 THEN 'Y' ELSE 'N' END AS SUCC_YN FROM MSP_JUO_SUB_INFO SUB WHERE SUB.ITEM_ID IS NOT NULL ) A, --가장 최근 건 성공 여부 ( SELECT ITEM_ID, SUCC_YN FROM ( SELECT ROW_NUMBER() OVER(PARTITION BY ITEM_ID ORDER BY REGST_DTTM DESC) AS HIST_ROW_NUM, ITEM_ID, SUCC_YN FROM KTIS_KNOTE_SCAN_HIST_ALL ) WHERE HIST_ROW_NUM = 1 ) B WHERE A.ITEM_ID = B.ITEM_ID(+)
AND LST_COM_ACTV_DATE BETWEEN #{srchStrtDt} AND #{srchEndDt}
AND A.CONTRACT_NUM = #{srchVal}
AND A.ITEM_ID = #{srchVal}
AND A.SUCC_YN = #{srchSuccYn}
AND B.SUCC_YN IS NULL
AND B.SUCC_YN = #{srchSuccRecentYn}
ORDER BY LST_COM_ACTV_DATE DESC

/* StatsMgmtMapper.getAppFormSyncListExcel */ WITH KTIS_KNOTE_SCAN_HIST_ALL AS ( SELECT ITEM_ID, REGST_DTTM,'Y' AS SUCC_YN FROM KIS_KNOTE_SCAN_HIST UNION ALL SELECT ITEM_ID, REGST_DTTM, 'N' AS SUCC_YN FROM KIS_KNOTE_SCAN_FAIL WHERE RSLT_CD != '2001' ) SELECT A.LST_COM_ACTV_DATE, TO_CHAR(TO_DATE(LST_COM_ACTV_DATE, 'YYYY-MM-DD'), 'YYYY-MM-DD') AS LST_COM_ACTV_DATE_VAL, A.CONTRACT_NUM, A.ITEM_ID, DECODE(A.SUCC_YN, 'Y', '존재', '미존재') AS SUCC_YN, DECODE(B.SUCC_YN, 'Y', '성공', 'N', '실패', '미존재') AS SUCC_RECENT_YN FROM ( SELECT SUB.LST_COM_ACTV_DATE, SUB.CONTRACT_NUM, SUB.ITEM_ID, CASE WHEN(SELECT COUNT(ITEM_ID) FROM KIS_KNOTE_SCAN_HIST WHERE ITEM_ID = SUB.ITEM_ID) > 0 THEN 'Y' ELSE 'N' END AS SUCC_YN FROM MSP_JUO_SUB_INFO SUB WHERE SUB.ITEM_ID IS NOT NULL ) A, --가장 최근 건 성공 여부 ( SELECT ITEM_ID, SUCC_YN FROM ( SELECT ROW_NUMBER() OVER(PARTITION BY ITEM_ID ORDER BY REGST_DTTM DESC) AS HIST_ROW_NUM, ITEM_ID, SUCC_YN FROM KTIS_KNOTE_SCAN_HIST_ALL ) WHERE HIST_ROW_NUM = 1 ) B WHERE A.ITEM_ID = B.ITEM_ID(+)
AND LST_COM_ACTV_DATE BETWEEN #{srchStrtDt} AND #{srchEndDt}
AND A.CONTRACT_NUM = #{srchVal}
AND A.ITEM_ID = #{srchVal}
AND A.SUCC_YN = #{srchSuccYn}
AND B.SUCC_YN IS NULL
AND B.SUCC_YN = #{srchSuccRecentYn}
ORDER BY LST_COM_ACTV_DATE DESC

/*StatsMgmtMapper.getDisPrmtChkList*/
SELECT A.REG_SEQ , DECODE(A.CHK_TYPE, 'DUP', '중복', '미처리') AS CHK_TYPE , A.CONTRACT_NUM , A.EFFECTIVE_DT , A.EFFECTIVE_DATE , A.PRMT_ID , CASE WHEN A.PRMT_ID LIKE 'F%' THEN (SELECT PRMT_NM FROM MSP_DIS_MST WHERE PRMT_ID = A.PRMT_ID) WHEN A.PRMT_ID LIKE 'C%' THEN (SELECT PRMT_NM FROM MSP_CHRG_PRMT WHERE PRMT_ID = A.PRMT_ID) ELSE '' END AS PRMT_NM , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0091' AND CD_VAL = A.EVNT_CD) AS EVNT_CD , A.RSLT_CD , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0095' AND CD_VAL = A.RSLT_CD) AS RSLT_DESC , NVL(A.PROC_YN, 'N') AS PROC_YN , A.PROC_MEMO , A.PROC_ID , TO_CHAR(A.PROC_DATE, 'YYYYMMDDHH24MISS') AS PROC_DATE FROM MSP_DIS_PRC_CHK A WHERE 1 = 1
AND A.EFFECTIVE_DT BETWEEN #{srchStrtDt} AND #{srchEndDt}
AND A.CONTRACT_NUM IN ( SELECT CONTRACT_NUM FROM MSP_JUO_SUB_INFO WHERE SUB_LINK_NAME = #{searchName} )
AND A.CONTRACT_NUM = #{searchName}
AND A.CONTRACT_NUM IN ( SELECT CONTRACT_NUM FROM MSP_JUO_SUB_INFO WHERE SUBSCRIBER_NO = #{searchName} )
AND A.CHK_TYPE = #{chkType}
AND A.RSLT_CD = #{rsltCd}
AND A.PROC_YN = #{procYn}
AND A.EVNT_CD = #{evntCd}
ORDER BY REG_SEQ DESC

/*StatsMgmtMapper.getDisPrmtChkListExcel*/ SELECT A.REG_SEQ , DECODE(A.CHK_TYPE, 'DUP', '중복', '미처리') AS CHK_TYPE , A.CONTRACT_NUM , A.EFFECTIVE_DT , A.EFFECTIVE_DATE , A.PRMT_ID , CASE WHEN A.PRMT_ID LIKE 'F%' THEN (SELECT PRMT_NM FROM MSP_DIS_MST WHERE PRMT_ID = A.PRMT_ID) WHEN A.PRMT_ID LIKE 'C%' THEN (SELECT PRMT_NM FROM MSP_CHRG_PRMT WHERE PRMT_ID = A.PRMT_ID) ELSE '' END AS PRMT_NM , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0091' AND CD_VAL = A.EVNT_CD) AS EVNT_CD , A.RSLT_CD , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0095' AND CD_VAL = A.RSLT_CD) AS RSLT_DESC , NVL(A.PROC_YN, 'N') AS PROC_YN , A.PROC_MEMO , A.PROC_ID , TO_CHAR(A.PROC_DATE, 'YYYYMMDDHH24MISS') AS PROC_DATE FROM MSP_DIS_PRC_CHK A WHERE 1 = 1
AND A.EFFECTIVE_DT BETWEEN #{srchStrtDt} AND #{srchEndDt}
AND A.CONTRACT_NUM IN ( SELECT CONTRACT_NUM FROM MSP_JUO_SUB_INFO WHERE SUB_LINK_NAME = #{searchName} )
AND A.CONTRACT_NUM = #{searchName}
AND A.CONTRACT_NUM IN ( SELECT CONTRACT_NUM FROM MSP_JUO_SUB_INFO WHERE SUBSCRIBER_NO = #{searchName} )
AND A.CHK_TYPE = #{chkType}
AND A.RSLT_CD = #{rsltCd}
AND A.PROC_YN = #{procYn}
AND A.EVNT_CD = #{evntCd}
ORDER BY REG_SEQ DESC

