mapper.sql:
SELECT CHK_DT , CONTRACT_NUM , (SELECT BAN FROM MSP_JUO_SUB_INFO WHERE CONTRACT_NUM = A.CONTRACT_NUM) AS BAN , OPEN_DT , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'RCP9052' AND CD_VAL = EVNT_CD) AS EVNT_CD , EFFECTIVE_DATE , FN_GET_ORGNM(OPEN_AGNT_CD) AS AGENT_NM , FN_GET_ORGNM(SHOP_CD) AS SHOP_NM , LST_RATE_CD , FN_GET_RATENM(LST_RATE_CD) AS LST_RATE_NM , LST_RATE_AMT , DIS_AMT , KT_DIS_AMT , FN_GET_CODENM('CMN0097', CHK_RSLT) AS CHK_RSLT , PRMT_ID , CASE WHEN A.PRMT_ID LIKE 'F%' THEN (SELECT PRMT_NM FROM MSP_DIS_MST WHERE PRMT_ID = A.PRMT_ID) WHEN A.PRMT_ID LIKE 'C%' THEN (SELECT PRMT_NM FROM MSP_CHRG_PRMT WHERE PRMT_ID = A.PRMT_ID) ELSE '' END AS PRMT_NM , PRMT_SOCS , KT_SOCS , PRMT_SOCS_NM , KT_SOCS_NM , COMP_YN , COMP_MEMO , COMP_ID , TO_CHAR(COMP_DATE, 'YYYYMMDDHH24MISS') AS COMP_DATE , RTY_YN , RTY_RSLT , RTY_ID , TO_CHAR(RTY_DATE, 'YYYYMMDDHH24MISS') AS RTY_DATE , FN_GET_CODENM('RCP9004', REQ_BUY_TYPE) AS REQ_BUY_TYPE_NM , REQ_BUY_TYPE AS REQ_BUY_TYPE_S FROM MSP_DIS_DAILY_CHK A WHERE 1 = 1
AND CHK_DT BETWEEN #{srchStrtDt} AND #{srchEndDt}
AND CONTRACT_NUM IN (SELECT CONTRACT_NUM FROM MSP_JUO_SUB_INFO WHERE SUB_LINK_NAME = #{searchName})
AND CONTRACT_NUM = #{searchName}
AND CONTRACT_NUM IN (SELECT CONTRACT_NUM FROM MSP_JUO_SUB_INFO WHERE SUBSCRIBER_NO = #{searchName})
AND CONTRACT_NUM IN (SELECT CONTRACT_NUM FROM MSP_REQUEST_DTL WHERE LST_RATE_CD = #{searchName})
AND CONTRACT_NUM IN (SELECT CONTRACT_NUM FROM MSP_REQUEST_DTL WHERE LST_RATE_NM = #{searchName})
AND CONTRACT_NUM IN (SELECT CONTRACT_NUM FROM MSP_JUO_SUB_INFO WHERE BAN = #{searchName})
AND CHK_RSLT = #{chkRslt}
AND EVNT_CD = #{evntCd}
AND COMP_YN = #{compYn}
AND RTY_YN = #{rtyYn}
ORDER BY CHK_DT DESC, CONTRACT_NUM DESC

mapper.update:
/* StatsMgmtMapper.updateDisAddChkComp */
UPDATE MSP_DIS_DAILY_CHK
   SET RVISN_DTTM = SYSDATE
	   , COMP_YN = #{compYn}
	   , COMP_ID = #{userId}
	   , COMP_MEMO = #{compMemo}
	   , COMP_DATE = SYSDATE
 WHERE CHK_DT= #{chkDt}
   AND CONTRACT_NUM = #{contractNum}

/* StatsMgmtMapper.updateDisAddChkRty */
UPDATE MSP_DIS_DAILY_CHK
SET RVISN_DTTM = SYSDATE
	, RTY_YN = #{rtyYn}
	, RTY_RSLT = #{rtyRslt}
	, RTY_ID = #{userId}
	, RTY_DATE = SYSDATE
WHERE CHK_DT= #{chkDt}
AND CONTRACT_NUM = #{contractNum}

