/* StatsMgmtMapper.getDisAddSvcListByPrmtId */
SELECT SOC
FROM MSP_DIS_ADD
WHERE PRMT_ID = #{prmtId}

/* StatsMgmtMapper.getUsimChgHst */
SELECT TO_CHAR(TO_DATE(USIM.CHG_DTTM, 'YYYYMMDDHH24MISS'), 'YYYY-MM-DD HH24:MI:SS') USIM_CHG_DATE , USIM.CONTRACT_NUM , SUB.SVC_CNTR_NO , USIM.USIM_MODNM , USIM.USIM_NO , FN_GET_CODENM('MSP0003', SUB.SUB_STATUS) SUB_STATUS , TO_CHAR(TO_DATE(SUB.LST_COM_ACTV_DATE, 'YYYYMMDD'), 'YYYY-MM-DD') LST_COM_ACTV_DATE FROM MSP_USIM_CHG_HST USIM , MSP_JUO_SUB_INFO SUB WHERE USIM.CONTRACT_NUM = SUB.CONTRACT_NUM AND CHG_DTTM > '20251104235959' /* 11월4일까지 이력을 기준 데이터로 사용 */
AND USIM.CHG_DTTM BETWEEN #{srchStrtDt} || '000000' AND #{srchEndDt} || '235959'
AND USIM.CONTRACT_NUM = #{searchName}
AND SUB.SVC_CNTR_NO = #{searchName}
ORDER BY USIM.CHG_DTTM DESC

