SELECT TO_CHAR(SYSDATE, 'YYYYMMDD') || LPAD(NMCP_CUST_REQUEST_SEQ.NEXTVAL@DL_MCP, 5, '0') FROM DUAL
INSERT INTO NMCP_CUST_REQUEST_MST@DL_MCP ( CUST_REQ_SEQ , REQ_TYPE , USERID , CSTMR_NAME , MOBILE_NO , CSTMR_NATIVE_RRN , CONTRACT_NUM , CSTMR_TYPE , ONLINE_AUTH_TYPE , ONLINE_AUTH_INFO , CRET_ID , SYS_RDATE , ETC_MOBILE ) SELECT #{newCustReqSeq} , REQ_TYPE , USERID , CSTMR_NAME , MOBILE_NO , CSTMR_NATIVE_RRN , CONTRACT_NUM , CSTMR_TYPE , ONLINE_AUTH_TYPE , ONLINE_AUTH_INFO , #{sessionUserId, jdbcType=VARCHAR} , SYSDATE , ETC_MOBILE FROM NMCP_CUST_REQUEST_MST@DL_MCP WHERE CUST_REQ_SEQ = #{custReqSeq}
